    {"question_text": "What will this code produce for handling multipage data with session persistence?\n\nsession = requests.Session()\n\n# Login\nsession.post('http://site.com/api/login', json={'user': 'admin', 'key': 'secret'})\n\n# Fetch all pages\npage = 1\nall_data = []\nwhile True:\n    resp = session.get(f'http://site.com/api/data?page={page}')\n    data = resp.json()\n    if not data['items']:\n        break\n    all_data.extend(data['items'])\n    page += 1\n\nprint(f'Total items: {len(all_data)}')", "option_a": "It fetches only the first page", "option_b": "It logs in once and iterates through all pages using the authenticated session until no items remain", "option_c": "It re-authenticates for each page", "option_d": "It downloads data without authentication", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this BeautifulSoup code demonstrate about the .parent property?\n\nhtml = '<div id=\"outer\"><p id=\"inner\"><span>Text</span></p></div>'\nsoup = BeautifulSoup(html, 'html.parser')\nspan = soup.find('span')\nparents = [p.name for p in span.parents if p.name]\nprint(parents)", "option_a": "['p', 'div']", "option_b": "['div', 'p']", "option_c": "['span', 'p', 'div']", "option_d": "['p']", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for extracting data from an HTML table with merged cells?\n\nhtml = '<table><tr><td rowspan=\"2\">Category</td><td>Item 1</td></tr><tr><td>Item 2</td></tr></table>'\nsoup = BeautifulSoup(html, 'html.parser')\nrows = soup.find_all('tr')\nfor row in rows:\n    cells = row.find_all('td')\n    print([c.text for c in cells])", "option_a": "[['Category', 'Item 1'], ['Item 2']]", "option_b": "[['Category', 'Item 1'], ['Category', 'Item 2']]", "option_c": "[['Category'], ['Item 1', 'Item 2']]", "option_d": "Error - rowspan not supported", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the purpose of using a context manager with Selenium WebDriver?\n\nfrom selenium import webdriver\nfrom contextlib import contextmanager\n\n@contextmanager\ndef browser_session():\n    driver = webdriver.Chrome()\n    try:\n        yield driver\n    finally:\n        driver.quit()\n\nwith browser_session() as driver:\n    driver.get('http://example.com')", "option_a": "It prevents the browser from opening", "option_b": "It ensures the browser is properly closed even if an exception occurs", "option_c": "It runs the browser in headless mode", "option_d": "It creates multiple browser instances", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code do for handling JavaScript-generated pagination?\n\nfrom playwright.async_api import async_playwright\n\nasync def scrape_all_pages():\n    async with async_playwright() as p:\n        browser = await p.chromium.launch()\n        page = await browser.new_page()\n        await page.goto('http://site.com/products')\n        \n        all_products = []\n        while True:\n            products = await page.query_selector_all('.product')\n            for prod in products:\n                name = await prod.inner_text()\n                all_products.append(name)\n            \n            next_btn = await page.query_selector('button.next:not([disabled])')\n            if not next_btn:\n                break\n            await next_btn.click()\n            await page.wait_for_load_state('networkidle')", "option_a": "It only gets the first page of products", "option_b": "It scrolls the page infinitely", "option_c": "It downloads all pages simultaneously", "option_d": "It navigates through paginated content by clicking Next until disabled, collecting products from each page", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does BeautifulSoup's .unwrap() method do?\n\nhtml = '<p>Hello <b>World</b> today</p>'\nsoup = BeautifulSoup(html, 'html.parser')\nsoup.find('b').unwrap()\nprint(soup.find('p'))", "option_a": "<p>Hello World today</p>", "option_b": "<p>Hello <b>World</b> today</p>", "option_c": "<p>Hello today</p>", "option_d": "Error", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the primary consideration when choosing between CSS selectors and XPath in web scraping?", "option_a": "XPath is always faster than CSS selectors", "option_b": "CSS selectors are simpler for class/id selection; XPath is more powerful for text content, axes, and complex conditions", "option_c": "CSS selectors can do everything XPath can", "option_d": "XPath only works with XML, not HTML", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code produce when scraping with request fingerprinting?\n\nimport hashlib\n\ndef request_fingerprint(url, method='GET', body=None):\n    fp_data = f'{method}:{url}:{body or \"\"}'\n    return hashlib.sha256(fp_data.encode()).hexdigest()[:16]\n\n# Usage for deduplication\nseen_requests = set()\nfp = request_fingerprint('http://example.com/page1')\nif fp not in seen_requests:\n    seen_requests.add(fp)\n    # make request", "option_a": "It caches response content", "option_b": "It generates unique fingerprints for requests to avoid making duplicate requests", "option_c": "It encrypts the URL", "option_d": "It validates URL format", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy Item Pipeline pattern accomplish?\n\nclass DuplicateFilterPipeline:\n    def __init__(self):\n        self.seen_ids = set()\n    \n    def process_item(self, item, spider):\n        if item['product_id'] in self.seen_ids:\n            raise DropItem(f'Duplicate: {item[\"product_id\"]}')\n        self.seen_ids.add(item['product_id'])\n        return item", "option_a": "It filters out items with duplicate product_ids, dropping repeats", "option_b": "It processes all items including duplicates", "option_c": "It merges duplicate items", "option_d": "It logs all product IDs", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the correct way to handle websites that use HTTP/2?\n\nimport httpx\n\nasync with httpx.AsyncClient(http2=True) as client:\n    resp = await client.get('https://http2-site.com')", "option_a": "Use the requests library which supports HTTP/2 by default", "option_b": "Use httpx with http2=True, as the requests library doesn't natively support HTTP/2", "option_c": "HTTP/2 sites cannot be scraped", "option_d": "Add 'HTTP2: true' header to requests", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this pattern accomplish for conditional scraping based on Last-Modified headers?\n\ndef fetch_if_newer(url, last_modified_cache):\n    headers = {}\n    if url in last_modified_cache:\n        headers['If-Modified-Since'] = last_modified_cache[url]\n    \n    resp = requests.get(url, headers=headers)\n    if resp.status_code == 304:\n        return None  # Not changed\n    \n    if 'Last-Modified' in resp.headers:\n        last_modified_cache[url] = resp.headers['Last-Modified']\n    return resp.text", "option_a": "It always downloads the full page", "option_b": "It uses conditional HTTP requests to only download pages that have been modified since the last fetch", "option_c": "It checks if the URL is valid", "option_d": "It caches responses in memory forever", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does soup.find('div', class_=re.compile(r'^product-')) match?\n\nimport re\nhtml = '<div class=\"product-card\">A</div><div class=\"product-list\">B</div><div class=\"featured-product\">C</div>'\nsoup = BeautifulSoup(html, 'html.parser')\nresult = soup.find_all('div', class_=re.compile(r'^product-'))\nprint([d.text for d in result])", "option_a": "['A', 'B', 'C']", "option_b": "['A', 'B']", "option_c": "['C']", "option_d": "['A']", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the correct way to handle sites that require TLS client certificates?\n\nresp = requests.get('https://secure-site.com/api', cert=('/path/to/client.cert', '/path/to/client.key'))", "option_a": "The cert parameter specifies the client certificate and key for mutual TLS authentication", "option_b": "The cert parameter specifies the CA bundle for verification", "option_c": "This disables TLS entirely", "option_d": "This only works with HTTP, not HTTPS", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Playwright interception pattern accomplish?\n\nasync def intercept_response(response):\n    if '/api/products' in response.url and response.status == 200:\n        data = await response.json()\n        products.extend(data['items'])\n\npage.on('response', intercept_response)\nawait page.goto('http://spa-site.com/shop')", "option_a": "It blocks API responses", "option_b": "It intercepts and captures API response data as the browser makes requests, without additional network calls", "option_c": "It modifies API responses before they reach the page", "option_d": "It only works with GET requests", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this code that uses BeautifulSoup's .replace_with()?\n\nhtml = '<p>Price: <span class=\"old\">$50</span> <span class=\"new\">$30</span></p>'\nsoup = BeautifulSoup(html, 'html.parser')\nold_price = soup.find('span', class_='old')\nold_price.replace_with('')\nprint(soup.find('p').get_text(strip=True))", "option_a": "Price: $50 $30", "option_b": "$30", "option_c": "Price:$30", "option_d": "Price: $30", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this async generator pattern accomplish for memory-efficient scraping?\n\nasync def scrape_pages(urls):\n    async with aiohttp.ClientSession() as session:\n        for url in urls:\n            async with session.get(url) as resp:\n                html = await resp.text()\n                soup = BeautifulSoup(html, 'html.parser')\n                for item in extract_items(soup):\n                    yield item\n\nasync for item in scrape_pages(url_list):\n    process(item)", "option_a": "It loads all items into memory at once", "option_b": "It yields items one at a time as they're scraped, keeping memory usage constant", "option_c": "It only processes the first item", "option_d": "It blocks until all pages are scraped", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy middleware accomplish for handling redirects?\n\nclass CustomRedirectMiddleware:\n    def process_response(self, request, response, spider):\n        if response.status in [301, 302]:\n            redirect_url = response.headers.get('Location', b'').decode()\n            spider.logger.info(f'Redirect: {request.url} -> {redirect_url}')\n            if '/login' in redirect_url:\n                raise IgnoreRequest('Redirect to login - session expired')\n        return response", "option_a": "It follows all redirects blindly", "option_b": "It logs redirects and drops requests that redirect to login pages (indicating expired sessions)", "option_c": "It blocks all redirects", "option_d": "It caches redirect URLs", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling websites with different encodings?\n\nimport chardet\n\ndef smart_decode(content_bytes):\n    detected = chardet.detect(content_bytes)\n    encoding = detected['encoding'] or 'utf-8'\n    return content_bytes.decode(encoding, errors='replace')", "option_a": "It always uses UTF-8 encoding", "option_b": "It converts all text to ASCII", "option_c": "It auto-detects the encoding of raw bytes and decodes accordingly, with fallback to UTF-8", "option_d": "It removes non-ASCII characters", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this BeautifulSoup code?\n\nhtml = '<img src=\"image.jpg\" alt=\"Product\" width=\"200\" />'\nsoup = BeautifulSoup(html, 'html.parser')\nimg = soup.find('img')\nprint(img.attrs)", "option_a": "{'src': 'image.jpg', 'alt': 'Product', 'width': '200'}", "option_b": "{'src': 'image.jpg'}", "option_c": "['src', 'alt', 'width']", "option_d": "None", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the correct way to simulate browser fingerprint characteristics to avoid detection?\n\nfrom selenium import webdriver\noptions = webdriver.ChromeOptions()\noptions.add_argument('--disable-blink-features=AutomationControlled')\noptions.add_experimental_option('excludeSwitches', ['enable-automation'])\noptions.add_experimental_option('useAutomationExtension', False)\ndriver = webdriver.Chrome(options=options)", "option_a": "This makes Selenium undetectable in all cases", "option_b": "This only affects the User-Agent string", "option_c": "This enables automation features", "option_d": "This removes common automation indicators that bot-detection scripts look for", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy spider accomplish with the errback parameter?\n\ndef start_requests(self):\n    yield scrapy.Request(url, callback=self.parse, errback=self.handle_error)\n\ndef handle_error(self, failure):\n    self.logger.error(f'Request failed: {failure.request.url}')\n    if failure.check(TimeoutError):\n        yield failure.request.copy()", "option_a": "It prevents all errors", "option_b": "It handles failed requests by logging the error and retrying timeout failures", "option_c": "It stops the spider on any error", "option_d": "It only handles 404 errors", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for saving scraped data to SQLite?\n\nimport sqlite3\n\nclass SQLiteStorage:\n    def __init__(self, db_path):\n        self.conn = sqlite3.connect(db_path)\n        self.conn.execute('''CREATE TABLE IF NOT EXISTS products\n            (id TEXT PRIMARY KEY, name TEXT, price REAL, scraped_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)''')\n    \n    def save(self, item):\n        self.conn.execute(\n            'INSERT OR REPLACE INTO products (id, name, price) VALUES (?, ?, ?)',\n            (item['id'], item['name'], item['price'])\n        )\n        self.conn.commit()", "option_a": "It stores data in a CSV file", "option_b": "It only reads from the database", "option_c": "It creates a SQLite database with upsert logic (insert or update) and automatic timestamps", "option_d": "It deletes existing data before inserting", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this BeautifulSoup code output when using .stripped_strings?\n\nhtml = '<div>  Hello  <p>  World  </p>  End  </div>'\nsoup = BeautifulSoup(html, 'html.parser')\nresult = list(soup.find('div').stripped_strings)\nprint(result)", "option_a": "['Hello', 'World', 'End']", "option_b": "['  Hello  ', '  World  ', '  End  ']", "option_c": "['Hello World End']", "option_d": "['Hello  World  End']", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this code demonstrating CSS sibling selectors in BeautifulSoup?\n\nhtml = '<div><h2>Title</h2><p>First</p><p>Second</p></div>'\nsoup = BeautifulSoup(html, 'html.parser')\nresult = soup.select('h2 ~ p')\nprint([p.text for p in result])", "option_a": "['First', 'Second']", "option_b": "['First']", "option_c": "['Second']", "option_d": "[]", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does h2 + p select compared to h2 ~ p in CSS selectors?\n\nhtml = '<div><h2>Title</h2><p>First</p><p>Second</p></div>'", "option_a": "They select the same elements", "option_b": "h2 + p selects only the immediately adjacent sibling p; h2 ~ p selects all subsequent sibling p elements", "option_c": "h2 + p selects all p elements; h2 ~ p selects only the first", "option_d": "+ is not a valid CSS combinator", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy spider accomplish with meta passing?\n\ndef parse_listing(self, response):\n    for product in response.css('.product'):\n        detail_url = product.css('a::attr(href)').get()\n        yield scrapy.Request(\n            response.urljoin(detail_url),\n            callback=self.parse_detail,\n            meta={'category': response.meta.get('category', 'unknown')}\n        )\n\ndef parse_detail(self, response):\n    yield {\n        'title': response.css('h1::text').get(),\n        'category': response.meta['category']\n    }", "option_a": "It passes metadata between request/response pairs to maintain context across callbacks", "option_b": "It stores data in cookies", "option_c": "It modifies HTTP headers", "option_d": "It creates duplicate requests", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this code for extracting data attributes?\n\nhtml = '<div data-product-id=\"ABC123\" data-category=\"electronics\" data-price=\"49.99\">Item</div>'\nsoup = BeautifulSoup(html, 'html.parser')\ndiv = soup.find('div')\ndata_attrs = {k: v for k, v in div.attrs.items() if k.startswith('data-')}\nprint(data_attrs)", "option_a": "{'data-product-id': 'ABC123', 'data-category': 'electronics', 'data-price': '49.99'}", "option_b": "{'product-id': 'ABC123'}", "option_c": "{}", "option_d": "['ABC123', 'electronics', '49.99']", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for handling sites that serve different content based on cookies?\n\nsession = requests.Session()\n# First visit to get session cookie\nsession.get('http://site.com')\n# Check what cookies were set\nprint(session.cookies.get_dict())\n# Now requests will include these cookies automatically", "option_a": "It deletes all cookies", "option_b": "It establishes a session, captures cookies from the initial visit, and automatically sends them with subsequent requests", "option_c": "It manually creates cookies", "option_d": "It only sends cookies once", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Selenium JavaScript injection accomplish for scraping?\n\ndriver.execute_script(\"\"\"\n    Object.defineProperty(navigator, 'webdriver', {get: () => undefined});\n\"\"\")", "option_a": "It enables webdriver detection", "option_b": "It sets the webdriver to a custom value", "option_c": "It crashes the browser", "option_d": "It removes the navigator.webdriver flag that many sites check to detect Selenium automation", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the correct way to extract text from specific child nodes only in BeautifulSoup?\n\nhtml = '<p>Text <a href=\"#\">Link</a> More <span>Hidden</span> End</p>'\nsoup = BeautifulSoup(html, 'html.parser')\np = soup.find('p')\n# Get only direct text nodes, not text from children\nresult = p.find_all(string=True, recursive=False)\nprint(result)", "option_a": "['Text ', ' More ', ' End']", "option_b": "['Text Link More Hidden End']", "option_c": "['Text ', ' Link', ' More ', 'Hidden', ' End']", "option_d": "[]", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this aiohttp retry pattern accomplish?\n\nasync def fetch_with_retry(session, url, max_retries=3):\n    for attempt in range(max_retries):\n        try:\n            async with session.get(url, timeout=aiohttp.ClientTimeout(total=10)) as resp:\n                if resp.status == 200:\n                    return await resp.text()\n                elif resp.status == 429:\n                    await asyncio.sleep(2 ** attempt)\n                else:\n                    return None\n        except (aiohttp.ClientError, asyncio.TimeoutError):\n            if attempt == max_retries - 1:\n                return None\n            await asyncio.sleep(1)", "option_a": "It only handles 200 responses", "option_b": "It retries on rate limiting (429) with exponential backoff and on network errors with fixed delay", "option_c": "It never retries", "option_d": "It retries all status codes equally", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does the following Scrapy ItemLoader pattern accomplish?\n\nfrom scrapy.loader import ItemLoader\nfrom scrapy.loader.processors import TakeFirst, MapCompose\n\ndef parse_product(self, response):\n    loader = ItemLoader(item=ProductItem(), response=response)\n    loader.add_css('name', 'h1.product-title::text')\n    loader.add_css('price', '.price::text', MapCompose(lambda x: x.replace('$', '')))\n    loader.add_value('url', response.url)\n    return loader.load_item()", "option_a": "It only extracts the URL", "option_b": "It creates an empty Item", "option_c": "It uses declarative extraction rules with processors to extract, clean, and load data into an Item", "option_d": "It validates the HTML structure", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code demonstrate about handling HTTP basic auth with requests?\n\nfrom requests.auth import HTTPBasicAuth\n\nresp = requests.get('http://api.example.com/data', auth=HTTPBasicAuth('user', 'pass'))\n# Equivalent shorthand:\nresp = requests.get('http://api.example.com/data', auth=('user', 'pass'))", "option_a": "The tuple form and HTTPBasicAuth are equivalent, both send Base64 encoded credentials in the Authorization header", "option_b": "Only HTTPBasicAuth works correctly", "option_c": "The tuple form sends plain text credentials", "option_d": "Both forms use OAuth2", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this BeautifulSoup code?\n\nhtml = '<div><span>A</span>Text<span>B</span></div>'\nsoup = BeautifulSoup(html, 'html.parser')\ndiv = soup.find('div')\nresult = div.get_text(separator='|')\nprint(result)", "option_a": "A|Text|B", "option_b": "ATextB", "option_c": "A|B", "option_d": "|A|Text|B|", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this scraping pattern with a rotating proxy pool accomplish?\n\nimport requests\nfrom itertools import cycle\n\nclass ProxyRotator:\n    def __init__(self, proxy_list):\n        self.proxy_cycle = cycle(proxy_list)\n        self.failed_proxies = set()\n    \n    def get_proxy(self):\n        for _ in range(len(self.proxy_cycle)):\n            proxy = next(self.proxy_cycle)\n            if proxy not in self.failed_proxies:\n                return proxy\n        return None\n    \n    def mark_failed(self, proxy):\n        self.failed_proxies.add(proxy)", "option_a": "It uses the same proxy for all requests", "option_b": "It rotates through proxies while tracking and skipping previously failed ones", "option_c": "It validates all proxies before use", "option_d": "It creates new proxy servers", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Selenium frame handling code accomplish?\n\nfrom selenium.webdriver.common.by import By\n\n# Switch to iframe\niframe = driver.find_element(By.CSS_SELECTOR, 'iframe#content-frame')\ndriver.switch_to.frame(iframe)\n\n# Interact with elements inside iframe\ndata = driver.find_element(By.CLASS_NAME, 'data-table').text\n\n# Switch back to main document\ndriver.switch_to.default_content()", "option_a": "It opens a new browser window", "option_b": "It switches context to an iframe element to access its content, then returns to the main page", "option_c": "It deletes the iframe", "option_d": "It creates a new iframe", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for polite scraping?\n\nimport time\nimport random\n\ndef polite_delay(min_delay=1, max_delay=3):\n    delay = random.uniform(min_delay, max_delay)\n    time.sleep(delay)\n\nfor url in urls_to_scrape:\n    polite_delay()\n    response = requests.get(url)", "option_a": "It makes requests as fast as possible", "option_b": "It always waits exactly 2 seconds", "option_c": "It adds randomized delays between requests to mimic human behavior and reduce server load", "option_d": "It only delays on error responses", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this XPath expression select?\n\n//a[starts-with(@href, '/category/') and @class='active']", "option_a": "All active links whose href starts with '/category/'", "option_b": "Only inactive category links", "option_c": "All links on the page", "option_d": "Links where href exactly equals '/category/'", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code do for extracting open graph metadata?\n\nhtml = '''<head>\n<meta property=\"og:title\" content=\"Article Title\">\n<meta property=\"og:description\" content=\"Description here\">\n<meta property=\"og:image\" content=\"http://img.com/pic.jpg\">\n</head>'''\nsoup = BeautifulSoup(html, 'html.parser')\nog_data = {}\nfor meta in soup.find_all('meta', property=lambda x: x and x.startswith('og:')):\n    key = meta['property'].replace('og:', '')\n    og_data[key] = meta['content']\nprint(og_data)", "option_a": "{'title': 'Article Title', 'description': 'Description here', 'image': 'http://img.com/pic.jpg'}", "option_b": "{}", "option_c": "['og:title', 'og:description', 'og:image']", "option_d": "Error", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does the HTTPCACHE_ENABLED setting do in Scrapy?\n\nHTTPCACHE_ENABLED = True\nHTTPCACHE_EXPIRATION_SECS = 3600\nHTTPCACHE_DIR = 'httpcache'", "option_a": "It disables caching", "option_b": "It caches only images", "option_c": "It caches HTTP responses locally for 1 hour, avoiding re-downloading unchanged pages during development", "option_d": "It stores all responses in memory permanently", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling gzip-encoded responses manually?\n\nimport gzip\nfrom io import BytesIO\n\nresp = requests.get(url, headers={'Accept-Encoding': 'gzip'})\nif resp.headers.get('Content-Encoding') == 'gzip':\n    decompressed = gzip.decompress(resp.content)\n    text = decompressed.decode('utf-8')\nelse:\n    text = resp.text", "option_a": "This is unnecessary - requests automatically decompresses gzip responses", "option_b": "It manually decompresses gzip content when needed", "option_c": "It compresses the response", "option_d": "It only works with binary files", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the purpose of Scrapy's CLOSESPIDER_ITEMCOUNT setting?\n\nCLOSESPIDER_ITEMCOUNT = 100", "option_a": "It closes the spider after scraping 100 items, useful for testing or sampling", "option_b": "It limits the spider to 100 requests", "option_c": "It closes after 100 seconds", "option_d": "It sets the maximum page count", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this BeautifulSoup code demonstrate about the .new_tag() method?\n\nsoup = BeautifulSoup('<div></div>', 'html.parser')\nnew_p = soup.new_tag('p', attrs={'class': 'added'})\nnew_p.string = 'New content'\nsoup.div.append(new_p)\nprint(soup)", "option_a": "<div><p class=\"added\">New content</p></div>", "option_b": "<div></div><p>New content</p>", "option_c": "<div></div>", "option_d": "Error", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
