    {"question_text": "What does this code accomplish for handling websites that use content negotiation?\n\n# Request JSON version of a page\nheaders_json = {'Accept': 'application/json'}\nresp_json = requests.get('http://api.site.com/data', headers=headers_json)\n\n# Request HTML version\nheaders_html = {'Accept': 'text/html'}\nresp_html = requests.get('http://api.site.com/data', headers=headers_html)", "option_a": "Both requests return the same content", "option_b": "It uses the Accept header to request different representations of the same resource", "option_c": "It sends the content type of the request body", "option_d": "It only works with POST requests", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy spider accomplish with the process_links method?\n\nfrom scrapy.spiders import CrawlSpider, Rule\nfrom scrapy.linkextractors import LinkExtractor\n\nclass FilteredSpider(CrawlSpider):\n    rules = [\n        Rule(LinkExtractor(), callback='parse_page', process_links='filter_links'),\n    ]\n    \n    def filter_links(self, links):\n        return [link for link in links if 'logout' not in link.url and 'admin' not in link.url]", "option_a": "It filters out unwanted links (logout, admin) before they're scheduled for crawling", "option_b": "It follows all links without filtering", "option_c": "It only follows logout links", "option_d": "It modifies link text", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for handling JavaScript-rendered content without a full browser?\n\nimport requests_html\n\nsession = requests_html.HTMLSession()\nresp = session.get('http://js-site.com')\nresp.html.render(timeout=20, sleep=2)\n# Now resp.html contains the rendered DOM\nlinks = resp.html.find('a.dynamic-link')", "option_a": "It uses pure HTTP without any rendering", "option_b": "It only handles static HTML", "option_c": "It uses requests-html library which includes a headless Chromium renderer for JavaScript execution", "option_d": "It downloads JavaScript files without executing them", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the correct way to handle scraping results that need to be deduplicated across multiple runs?\n\nimport sqlite3\n\nclass PersistentDeduplicator:\n    def __init__(self, db_path='seen.db'):\n        self.conn = sqlite3.connect(db_path)\n        self.conn.execute('CREATE TABLE IF NOT EXISTS seen (url_hash TEXT PRIMARY KEY, first_seen TIMESTAMP DEFAULT CURRENT_TIMESTAMP)')\n    \n    def is_new(self, url):\n        import hashlib\n        url_hash = hashlib.md5(url.encode()).hexdigest()\n        try:\n            self.conn.execute('INSERT INTO seen (url_hash) VALUES (?)', (url_hash,))\n            self.conn.commit()\n            return True\n        except sqlite3.IntegrityError:\n            return False", "option_a": "It checks in-memory only, losing state on restart", "option_b": "It uses SQLite for persistent URL deduplication that survives across scraper restarts", "option_c": "It deletes duplicate URLs from the database", "option_d": "It only works with a single URL", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern demonstrate about handling HTTP redirects manually?\n\nresp = requests.get('http://short.link/abc', allow_redirects=False)\nredirect_chain = []\nwhile resp.status_code in (301, 302, 303, 307, 308):\n    location = resp.headers['Location']\n    redirect_chain.append(location)\n    resp = requests.get(location, allow_redirects=False)\nprint(f'Final URL: {redirect_chain[-1] if redirect_chain else resp.url}')", "option_a": "It follows redirects automatically", "option_b": "It only follows 301 redirects", "option_c": "It blocks all redirects", "option_d": "It manually traces the redirect chain to log each hop before reaching the final URL", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy extension accomplish for monitoring spider health?\n\nfrom scrapy import signals\nimport time\n\nclass SpiderHealthCheck:\n    def __init__(self):\n        self.last_item_time = time.time()\n        self.stall_timeout = 300  # 5 minutes\n    \n    @classmethod\n    def from_crawler(cls, crawler):\n        ext = cls()\n        crawler.signals.connect(ext.item_scraped, signals.item_scraped)\n        return ext\n    \n    def item_scraped(self, item, spider):\n        self.last_item_time = time.time()\n    \n    def is_stalled(self):\n        return (time.time() - self.last_item_time) > self.stall_timeout", "option_a": "It speeds up the spider", "option_b": "It restarts the spider automatically", "option_c": "It counts total items", "option_d": "It detects when the spider hasn't scraped any items for 5 minutes, indicating it may be stuck", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for extracting text while preserving paragraph structure?\n\ndef extract_article_text(soup):\n    article = soup.find('article')\n    paragraphs = []\n    for p in article.find_all(['p', 'h1', 'h2', 'h3']):\n        text = p.get_text(strip=True)\n        if text:\n            paragraphs.append(text)\n    return '\\n\\n'.join(paragraphs)", "option_a": "It extracts all HTML from the article", "option_b": "It extracts text from paragraphs and headings, joining them with double newlines to preserve structure", "option_c": "It only extracts headings", "option_d": "It removes all paragraph formatting", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Selenium code accomplish for handling file downloads?\n\nfrom selenium.webdriver.chrome.options import Options\n\noptions = Options()\nprefs = {\n    'download.default_directory': '/tmp/downloads',\n    'download.prompt_for_download': False,\n    'download.directory_upgrade': True\n}\noptions.add_experimental_option('prefs', prefs)\ndriver = webdriver.Chrome(options=options)", "option_a": "It blocks all downloads", "option_b": "It configures Chrome to automatically download files to a specific directory without prompting", "option_c": "It uploads files", "option_d": "It only downloads images", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this BeautifulSoup code that uses the limit parameter?\n\nhtml = '<div><p>1</p><p>2</p><p>3</p><p>4</p><p>5</p></div>'\nsoup = BeautifulSoup(html, 'html.parser')\nresult = soup.find_all('p', limit=3)\nprint(len(result), [p.text for p in result])", "option_a": "3 ['1', '2', '3']", "option_b": "5 ['1', '2', '3', '4', '5']", "option_c": "3 ['3', '4', '5']", "option_d": "1 ['1']", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for scraping websites with anti-bot JavaScript challenges?\n\nimport undetected_chromedriver as uc\n\ndriver = uc.Chrome(headless=True)\ndriver.get('https://protected-site.com')\n# undetected-chromedriver patches Chrome to avoid common detection methods", "option_a": "It uses a standard ChromeDriver", "option_b": "It uses a patched ChromeDriver that avoids common Selenium detection techniques used by anti-bot services", "option_c": "It disables JavaScript", "option_d": "It only works with Firefox", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this async scraping pattern with retry and backoff accomplish?\n\nimport asyncio\nimport aiohttp\nfrom tenacity import retry, stop_after_attempt, wait_exponential\n\n@retry(stop=stop_after_attempt(3), wait=wait_exponential(multiplier=1, max=10))\nasync def fetch_page(session, url):\n    async with session.get(url) as resp:\n        resp.raise_for_status()\n        return await resp.text()", "option_a": "It makes exactly one attempt per URL", "option_b": "It disables retries", "option_c": "It waits 10 seconds before every request", "option_d": "It uses the tenacity library to retry failed requests up to 3 times with exponential backoff (max 10s)", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for monitoring scraping throughput?\n\nimport time\nfrom collections import deque\n\nclass ThroughputMonitor:\n    def __init__(self, window_seconds=60):\n        self.timestamps = deque()\n        self.window = window_seconds\n    \n    def record(self):\n        now = time.time()\n        self.timestamps.append(now)\n        while self.timestamps and now - self.timestamps[0] > self.window:\n            self.timestamps.popleft()\n    \n    def get_rate(self):\n        return len(self.timestamps) / self.window if self.timestamps else 0", "option_a": "It counts total requests ever made", "option_b": "It tracks requests per second over a sliding time window for real-time throughput monitoring", "option_c": "It limits request rate", "option_d": "It only tracks errors", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling multipart form data during scraping?\n\nfiles = {'file': ('report.pdf', open('report.pdf', 'rb'), 'application/pdf')}\ndata = {'description': 'Monthly report'}\nresp = requests.post('http://site.com/upload', files=files, data=data)", "option_a": "It downloads a PDF file", "option_b": "It uploads a file with additional form data using multipart/form-data encoding", "option_c": "It only sends the form data without the file", "option_d": "It creates a PDF file locally", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this BeautifulSoup SoupStrainer accomplish for memory-efficient parsing?\n\nfrom bs4 import BeautifulSoup, SoupStrainer\n\nonly_links = SoupStrainer('a')\nsoup = BeautifulSoup(large_html, 'html.parser', parse_only=only_links)\nlinks = soup.find_all('a')", "option_a": "It parses the entire document then filters", "option_b": "It removes all links from the document", "option_c": "It only parses <a> tags, ignoring the rest of the document for memory efficiency", "option_d": "It validates link URLs", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for distributed scraping coordination?\n\nimport redis\n\nclass RedisURLQueue:\n    def __init__(self, redis_url='redis://localhost:6379'):\n        self.redis = redis.from_url(redis_url)\n        self.queue_key = 'scraper:urls'\n        self.seen_key = 'scraper:seen'\n    \n    def add_url(self, url):\n        if not self.redis.sismember(self.seen_key, url):\n            self.redis.sadd(self.seen_key, url)\n            self.redis.rpush(self.queue_key, url)\n    \n    def get_url(self):\n        return self.redis.lpop(self.queue_key)", "option_a": "It stores all data in Redis", "option_b": "It uses Redis for distributed URL queue management with deduplication, enabling multiple scraper instances to coordinate", "option_c": "It only caches responses", "option_d": "It tracks scraper errors", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this code for extracting table data with headers?\n\nhtml = '''<table>\n<tr><th>Name</th><th>Age</th><th>City</th></tr>\n<tr><td>Alice</td><td>30</td><td>NYC</td></tr>\n<tr><td>Bob</td><td>25</td><td>LA</td></tr>\n</table>'''\nsoup = BeautifulSoup(html, 'html.parser')\nheaders = [th.text for th in soup.select('tr:first-child th')]\nrows = [[td.text for td in tr.select('td')] for tr in soup.select('tr')[1:]]\nprint(dict(zip(headers, rows[0])))", "option_a": "{'Name': 'Alice', 'Age': '30', 'City': 'NYC'}", "option_b": "{'Alice': 'Name', '30': 'Age', 'NYC': 'City'}", "option_c": "[['Alice', '30', 'NYC'], ['Bob', '25', 'LA']]", "option_d": "Error", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy download handler configuration accomplish?\n\nDOWNLOAD_HANDLERS = {\n    's3': 'scrapy.core.downloader.handlers.s3.S3DownloadHandler',\n    'ftp': 'scrapy.core.downloader.handlers.ftp.FTPDownloadHandler',\n}", "option_a": "It disables HTTP downloads", "option_b": "It only downloads from S3", "option_c": "It enables Scrapy to download content from S3 buckets and FTP servers in addition to HTTP", "option_d": "It uploads scraped data to S3", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for extracting CSS class names from all elements?\n\nhtml = '<div class=\"a b\"><p class=\"c d e\">Text</p><span class=\"a f\">More</span></div>'\nsoup = BeautifulSoup(html, 'html.parser')\nall_classes = set()\nfor tag in soup.find_all(class_=True):\n    all_classes.update(tag['class'])\nprint(sorted(all_classes))", "option_a": "['a', 'b', 'c', 'd', 'e', 'f']", "option_b": "['a b', 'c d e', 'a f']", "option_c": "['a', 'b']", "option_d": "[]", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy spider middleware accomplish?\n\nclass DepthMiddleware:\n    def process_spider_output(self, response, result, spider):\n        for item_or_request in result:\n            if isinstance(item_or_request, scrapy.Request):\n                depth = response.meta.get('depth', 0) + 1\n                item_or_request.meta['depth'] = depth\n                if depth > spider.settings.getint('DEPTH_LIMIT', 0):\n                    continue  # Skip requests beyond depth limit\n            yield item_or_request", "option_a": "It increases spider speed", "option_b": "It tracks and enforces crawl depth, dropping requests that exceed the depth limit", "option_c": "It only processes items, not requests", "option_d": "It adds all requests regardless of depth", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the correct way to use BeautifulSoup with a custom tag filter function?\n\nhtml = '<div><p id=\"p1\">A</p><p>B</p><p id=\"p3\" class=\"highlight\">C</p></div>'\nsoup = BeautifulSoup(html, 'html.parser')\n\ndef has_id_and_class(tag):\n    return tag.name == 'p' and tag.has_attr('id') and tag.has_attr('class')\n\nresult = soup.find_all(has_id_and_class)\nprint([p.text for p in result])", "option_a": "['A', 'C']", "option_b": "['A', 'B', 'C']", "option_c": "['C']", "option_d": "[]", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling GraphQL API scraping?\n\nimport requests\n\nquery = '''\n{\n  products(first: 100, after: \"cursor123\") {\n    edges {\n      node {\n        id\n        name\n        price\n      }\n    }\n    pageInfo {\n      hasNextPage\n      endCursor\n    }\n  }\n}\n'''\n\nresp = requests.post('http://site.com/graphql', json={'query': query})\ndata = resp.json()", "option_a": "It makes a REST API call", "option_b": "It creates a database query", "option_c": "It scrapes HTML content", "option_d": "It sends a GraphQL query to fetch paginated product data from a GraphQL endpoint", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code demonstrate about handling HTML comments in BeautifulSoup?\n\nfrom bs4 import BeautifulSoup, Comment\n\nhtml = '<div>Visible<!-- Hidden data: secret123 -->More text</div>'\nsoup = BeautifulSoup(html, 'html.parser')\ncomments = soup.find_all(string=lambda text: isinstance(text, Comment))\nfor comment in comments:\n    print(comment.strip())", "option_a": "It prints 'Visible'", "option_b": "Hidden data: secret123", "option_c": "It removes all comments", "option_d": "It prints nothing", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern do for scraping price data with locale-aware parsing?\n\nimport locale\nimport re\n\ndef parse_price(price_str):\n    # Handle various formats: $1,234.56, \u20ac1.234,56, \u00a31234.56\n    cleaned = re.sub(r'[^\\d.,]', '', price_str)\n    # Determine decimal separator\n    if ',' in cleaned and '.' in cleaned:\n        if cleaned.rindex(',') > cleaned.rindex('.'):\n            cleaned = cleaned.replace('.', '').replace(',', '.')\n        else:\n            cleaned = cleaned.replace(',', '')\n    elif ',' in cleaned and len(cleaned.split(',')[-1]) == 2:\n        cleaned = cleaned.replace(',', '.')\n    return float(cleaned)", "option_a": "It only handles USD prices", "option_b": "It intelligently parses prices from different locale formats (US, European) into float values", "option_c": "It formats prices for display", "option_d": "It converts currencies", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Selenium network interception with Chrome DevTools Protocol accomplish?\n\nimport json\n\ndriver.execute_cdp_cmd('Network.enable', {})\ndriver.execute_cdp_cmd('Network.setExtraHTTPHeaders', {'headers': {'X-Custom': 'value'}})\n\n# Capture network responses\ndef get_network_responses(driver):\n    logs = driver.get_log('performance')\n    responses = []\n    for log in logs:\n        msg = json.loads(log['message'])['message']\n        if msg['method'] == 'Network.responseReceived':\n            responses.append(msg['params'])\n    return responses", "option_a": "It uses Chrome DevTools Protocol to add custom headers and capture network activity for analysis", "option_b": "It blocks all network requests", "option_c": "It modifies response bodies", "option_d": "It only works with POST requests", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this code for handling BeautifulSoup with multiple parsers?\n\nhtml = '<p><b>Bold <i>and italic</p>'\n\nsoup_html = BeautifulSoup(html, 'html.parser')\nsoup_lxml = BeautifulSoup(html, 'lxml')\n\nprint(len(soup_html.find_all('b')), len(soup_lxml.find_all('b')))", "option_a": "1 1", "option_b": "0 1", "option_c": "1 0", "option_d": "0 0", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing a breadth-first crawling strategy?\n\nfrom collections import deque\n\nclass BFSCrawler:\n    def __init__(self, start_url, max_depth=3):\n        self.queue = deque([(start_url, 0)])  # (url, depth)\n        self.visited = {start_url}\n    \n    def crawl(self):\n        while self.queue:\n            url, depth = self.queue.popleft()\n            if depth > self.max_depth:\n                continue\n            html = fetch(url)\n            process(html)\n            for link in extract_links(html):\n                if link not in self.visited:\n                    self.visited.add(link)\n                    self.queue.append((link, depth + 1))", "option_a": "It crawls pages depth-first", "option_b": "It crawls pages level by level (breadth-first), exploring all links at depth N before moving to depth N+1", "option_c": "It crawls randomly", "option_d": "It only crawls the start URL", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish when scraping requires maintaining a specific order of headers?\n\nfrom collections import OrderedDict\nfrom requests import Session\nfrom requests.adapters import HTTPAdapter\n\nsession = Session()\nsession.headers = OrderedDict([\n    ('Host', 'example.com'),\n    ('Connection', 'keep-alive'),\n    ('User-Agent', 'Mozilla/5.0 ...'),\n    ('Accept', 'text/html'),\n    ('Accept-Language', 'en-US'),\n])", "option_a": "Header order doesn't matter", "option_b": "It ensures headers are sent in a specific order, which some anti-bot systems check as a fingerprinting method", "option_c": "It removes duplicate headers", "option_d": "It only sends the first header", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this BeautifulSoup code output?\n\nhtml = '<select name=\"size\"><option value=\"S\">Small</option><option value=\"M\" selected>Medium</option><option value=\"L\">Large</option></select>'\nsoup = BeautifulSoup(html, 'html.parser')\noptions = {opt['value']: opt.text for opt in soup.find_all('option')}\nprint(options)", "option_a": "{'S': 'Small', 'M': 'Medium', 'L': 'Large'}", "option_b": "['S', 'M', 'L']", "option_c": "{'M': 'Medium'}", "option_d": "{'size': ['S', 'M', 'L']}", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for handling scraping rate limits with a leaky bucket algorithm?\n\nimport time\nimport threading\n\nclass LeakyBucket:\n    def __init__(self, rate, capacity):\n        self.rate = rate  # tokens per second\n        self.capacity = capacity\n        self.tokens = capacity\n        self.last_refill = time.time()\n        self.lock = threading.Lock()\n    \n    def acquire(self):\n        with self.lock:\n            now = time.time()\n            self.tokens = min(self.capacity, self.tokens + (now - self.last_refill) * self.rate)\n            self.last_refill = now\n            if self.tokens >= 1:\n                self.tokens -= 1\n                return True\n            return False\n    \n    def wait_for_token(self):\n        while not self.acquire():\n            time.sleep(0.1)", "option_a": "It allows unlimited requests", "option_b": "It only tracks request counts", "option_c": "It blocks all requests permanently", "option_d": "It implements a token bucket rate limiter that allows bursts up to capacity but limits sustained rate", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for scraping paginated content with unknown total pages?\n\ndef scrape_binary_search_total(base_url):\n    \"\"\"Find the last page using binary search\"\"\"\n    low, high = 1, 1\n    # Find upper bound\n    while page_exists(f'{base_url}?page={high}'):\n        high *= 2\n    # Binary search for exact last page\n    while low < high:\n        mid = (low + high) // 2\n        if page_exists(f'{base_url}?page={mid}'):\n            low = mid + 1\n        else:\n            high = mid\n    return low - 1", "option_a": "It linearly checks every page number", "option_b": "It uses binary search to efficiently find the total number of pages without checking each one", "option_c": "It always returns page 1", "option_d": "It downloads all pages simultaneously", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Playwright code accomplish for PDF scraping?\n\nasync with async_playwright() as p:\n    browser = await p.chromium.launch()\n    page = await browser.new_page()\n    await page.goto('http://site.com/report')\n    pdf_bytes = await page.pdf(format='A4', print_background=True)\n    with open('report.pdf', 'wb') as f:\n        f.write(pdf_bytes)", "option_a": "It downloads an existing PDF from a URL", "option_b": "It converts PDF to HTML", "option_c": "It renders a web page and saves it as a PDF file using the browser's print-to-PDF capability", "option_d": "It only works with static pages", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for validating scraped data quality?\n\ndef validate_product(item):\n    errors = []\n    if not item.get('name') or len(item['name']) < 2:\n        errors.append('Invalid name')\n    if not item.get('price') or not isinstance(item['price'], (int, float)) or item['price'] <= 0:\n        errors.append('Invalid price')\n    if item.get('url') and not item['url'].startswith('http'):\n        errors.append('Invalid URL')\n    return errors if errors else None", "option_a": "It formats data for display", "option_b": "It validates scraped items against business rules and returns error details for invalid data", "option_c": "It fixes invalid data automatically", "option_d": "It only checks URLs", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for converting scraped HTML tables to pandas DataFrames?\n\nimport pandas as pd\nfrom bs4 import BeautifulSoup\n\nhtml = requests.get('http://site.com/data-table').text\ntables = pd.read_html(html, attrs={'id': 'main-table'})\ndf = tables[0]\nprint(df.shape)", "option_a": "It creates a table from scratch", "option_b": "It creates HTML from a DataFrame", "option_c": "It only reads CSV files", "option_d": "It uses pandas read_html to parse HTML tables directly into DataFrames, filtered by table ID", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for scraping with automatic retries on specific HTTP status codes?\n\nfrom requests.adapters import HTTPAdapter\nfrom urllib3.util.retry import Retry\n\ndef create_resilient_session():\n    session = requests.Session()\n    retry_strategy = Retry(\n        total=5,\n        status_forcelist=[429, 500, 502, 503, 504],\n        allowed_methods=['GET', 'POST'],\n        backoff_factor=2\n    )\n    adapter = HTTPAdapter(max_retries=retry_strategy)\n    session.mount('http://', adapter)\n    session.mount('https://', adapter)\n    return session", "option_a": "It retries all requests regardless of status", "option_b": "It configures automatic retries with exponential backoff only for specific server error and rate limit status codes", "option_c": "It limits total requests to 5", "option_d": "It only retries GET requests", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code demonstrate about handling iframe content in BeautifulSoup?\n\nhtml = '<div><iframe src=\"http://other-site.com/widget\"></iframe></div>'\nsoup = BeautifulSoup(html, 'html.parser')\niframe = soup.find('iframe')\niframe_url = iframe['src']\n# Must fetch iframe content separately\niframe_content = requests.get(iframe_url).text\niframe_soup = BeautifulSoup(iframe_content, 'html.parser')", "option_a": "BeautifulSoup automatically loads iframe content", "option_b": "Iframe content must be fetched separately as BeautifulSoup only parses the iframe tag, not its remote content", "option_c": "Iframes cannot be scraped", "option_d": "The iframe src is always relative", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy spider accomplish with custom request priorities?\n\ndef parse(self, response):\n    # High priority: product detail pages\n    for link in response.css('.product a::attr(href)'):\n        yield scrapy.Request(link.get(), callback=self.parse_product, priority=1)\n    \n    # Low priority: pagination links\n    next_page = response.css('a.next::attr(href)').get()\n    if next_page:\n        yield scrapy.Request(next_page, callback=self.parse, priority=-1)", "option_a": "All requests have equal priority", "option_b": "Product pages are fetched before pagination pages, ensuring product data is collected first", "option_c": "Pagination pages are fetched first", "option_d": "Priority has no effect in Scrapy", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code output?\n\nfrom bs4 import BeautifulSoup\nhtml = '<div><p>Text with <br/> line break</p></div>'\nsoup = BeautifulSoup(html, 'html.parser')\np = soup.find('p')\ntext = p.get_text(separator='\\n')\nprint(repr(text))", "option_a": "'Text with \\n line break'", "option_b": "'Text with  line break'", "option_c": "'Text with \\nline break'", "option_d": "'Text with <br/> line break'", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for scraping APIs that use HMAC signature authentication?\n\nimport hmac\nimport hashlib\nimport time\n\ndef sign_request(api_key, api_secret, path):\n    timestamp = str(int(time.time()))\n    message = f'{timestamp}{path}'\n    signature = hmac.new(api_secret.encode(), message.encode(), hashlib.sha256).hexdigest()\n    return {\n        'X-API-Key': api_key,\n        'X-Timestamp': timestamp,\n        'X-Signature': signature\n    }", "option_a": "It encrypts the response", "option_b": "It creates a new API account", "option_c": "It validates the server certificate", "option_d": "It generates HMAC-signed authentication headers required by the API for request verification", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this BeautifulSoup code demonstrate about the .extract() method?\n\nhtml = '<div><p>Keep</p><script>remove me</script><p>Also keep</p></div>'\nsoup = BeautifulSoup(html, 'html.parser')\nfor script in soup.find_all('script'):\n    script.extract()\nprint(soup.div.get_text(strip=True))", "option_a": "KeepAlso keep", "option_b": "Keep remove me Also keep", "option_c": "remove me", "option_d": "Error", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the difference between .extract() and .decompose() in BeautifulSoup?", "option_a": "They are identical", "option_b": ".extract() removes the tag and returns it (can be reused); .decompose() removes and destroys it completely", "option_c": ".decompose() is faster than .extract()", "option_d": ".extract() only removes text; .decompose() removes tags", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for detecting and handling honeypot links?\n\ndef is_honeypot_link(tag):\n    # Common honeypot indicators\n    style = tag.get('style', '')\n    parent_style = tag.parent.get('style', '') if tag.parent else ''\n    \n    hidden_indicators = [\n        'display:none' in style.replace(' ', ''),\n        'display:none' in parent_style.replace(' ', ''),\n        'visibility:hidden' in style.replace(' ', ''),\n        tag.get('class') and 'hidden' in ' '.join(tag.get('class', [])),\n    ]\n    return any(hidden_indicators)", "option_a": "It detects links hidden via CSS that may be honeypot traps set by websites to catch scrapers", "option_b": "It follows all hidden links", "option_c": "It hides links from users", "option_d": "It only checks link validity", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy configuration accomplish for handling large responses?\n\nDOWNLOAD_MAXSIZE = 10 * 1024 * 1024  # 10 MB\nDOWNLOAD_WARNSIZE = 5 * 1024 * 1024   # 5 MB\nDOWNLOAD_TIMEOUT = 30", "option_a": "It downloads files of any size", "option_b": "It sets limits on response size (warn at 5MB, reject at 10MB) and a 30-second download timeout", "option_c": "It compresses all responses", "option_d": "It only affects upload sizes", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code output when parsing malformed HTML with missing closing tags?\n\nhtml = '<div><p>First<p>Second<p>Third</div>'\nsoup = BeautifulSoup(html, 'html.parser')\nprint(len(soup.find_all('p')))", "option_a": "1", "option_b": "3", "option_c": "2", "option_d": "0", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for scraping with proxy authentication?\n\nproxies = {\n    'http': 'http://user:password@proxy-server.com:8080',\n    'https': 'http://user:password@proxy-server.com:8080'\n}\nresp = requests.get('http://target-site.com', proxies=proxies)", "option_a": "It connects directly without a proxy", "option_b": "It routes the request through an authenticated proxy server, embedding credentials in the proxy URL", "option_c": "It authenticates with the target site", "option_d": "It creates a VPN connection", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code demonstrate about the requests library's prepared requests?\n\nfrom requests import Request, Session\n\nreq = Request('GET', 'http://example.com', headers={'Custom': 'Header'})\nprepared = req.prepare()\n\nsession = Session()\nresp = session.send(prepared, timeout=5)", "option_a": "Prepared requests can be inspected and modified before sending, useful for debugging", "option_b": "They are slower than regular requests", "option_c": "They cannot be used with sessions", "option_d": "They automatically retry on failure", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling websites with Content Security Policy headers?\n\n# Some sites set CSP headers that affect scraping tools\n# Selenium can ignore CSP:\noptions = webdriver.ChromeOptions()\noptions.add_argument('--disable-web-security')\noptions.add_argument('--allow-running-insecure-content')", "option_a": "It enforces stricter security", "option_b": "It encrypts all traffic", "option_c": "It adds CSP headers to requests", "option_d": "It disables browser security features that might block loading of cross-origin resources during scraping", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
