    {"question_text": "What does this Scrapy configuration for handling JavaScript accomplish?\n\n# In settings.py\nDOWNLOAD_HANDLERS = {\n    'http': 'scrapy_playwright.handler.ScrapyPlaywrightDownloadHandler',\n    'https': 'scrapy_playwright.handler.ScrapyPlaywrightDownloadHandler',\n}\nTWISTED_REACTOR = 'twisted.internet.asyncioreactor.AsyncioSelectorReactor'\n\n# In spider\nyield scrapy.Request(url, meta={'playwright': True})", "option_a": "It disables Playwright integration", "option_b": "It integrates Playwright with Scrapy to render JavaScript for specific requests while keeping Scrapy's architecture", "option_c": "It uses Selenium instead", "option_d": "It only works with HTTP, not HTTPS", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for structured logging in scrapers?\n\nimport logging\nimport json\n\nclass JSONFormatter(logging.Formatter):\n    def format(self, record):\n        log_data = {\n            'timestamp': self.formatTime(record),\n            'level': record.levelname,\n            'message': record.getMessage(),\n            'url': getattr(record, 'url', None),\n            'status_code': getattr(record, 'status_code', None),\n        }\n        return json.dumps(log_data)\n\nlogger = logging.getLogger('scraper')\nlogger.info('Page fetched', extra={'url': 'http://example.com', 'status_code': 200})", "option_a": "It formats logs as plain text", "option_b": "It outputs structured JSON logs with scraper-specific context like URL and status code for easy analysis", "option_c": "It disables logging", "option_d": "It only logs errors", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling scraping targets that use WebSocket communication?\n\nfrom playwright.async_api import async_playwright\n\nasync def capture_websocket_data(url):\n    async with async_playwright() as p:\n        browser = await p.chromium.launch()\n        page = await browser.new_page()\n        \n        ws_messages = []\n        page.on('websocket', lambda ws: ws.on('framereceived', lambda data: ws_messages.append(data)))\n        \n        await page.goto(url)\n        await page.wait_for_timeout(5000)\n        return ws_messages", "option_a": "It sends WebSocket messages", "option_b": "It uses Playwright to intercept and capture WebSocket messages received by the page", "option_c": "It blocks WebSocket connections", "option_d": "It creates a WebSocket server", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for building a configurable scraper pipeline?\n\nclass ScraperPipeline:\n    def __init__(self, steps=None):\n        self.steps = steps or []\n    \n    def add_step(self, func):\n        self.steps.append(func)\n        return self\n    \n    def process(self, data):\n        result = data\n        for step in self.steps:\n            result = step(result)\n            if result is None:\n                return None\n        return result\n\npipeline = ScraperPipeline()\npipeline.add_step(clean_html).add_step(extract_data).add_step(validate).add_step(store)", "option_a": "It runs all steps in parallel", "option_b": "It creates a configurable sequential pipeline where data flows through steps, stopping on None", "option_c": "It only runs the first step", "option_d": "It reverses the processing order", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this code for handling relative protocol URLs?\n\nfrom urllib.parse import urljoin\n\nbase = 'https://example.com/page'\nrelative = '//cdn.example.com/image.jpg'\nresult = urljoin(base, relative)\nprint(result)", "option_a": "https://cdn.example.com/image.jpg", "option_b": "http://cdn.example.com/image.jpg", "option_c": "//cdn.example.com/image.jpg", "option_d": "https://example.com//cdn.example.com/image.jpg", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing a polite crawler with adaptive rate limiting?\n\nclass AdaptiveRateLimiter:\n    def __init__(self, initial_delay=1.0):\n        self.delay = initial_delay\n    \n    def adjust(self, response_time):\n        if response_time > 5.0:\n            self.delay = min(self.delay * 2, 30)  # Server is slow, back off\n        elif response_time < 0.5 and self.delay > 0.5:\n            self.delay = max(self.delay * 0.8, 0.5)  # Server is fast, speed up\n    \n    def wait(self):\n        time.sleep(self.delay)", "option_a": "It always uses the same delay", "option_b": "It dynamically adjusts request delay based on server response times - slowing down when server is stressed", "option_c": "It only increases delay", "option_d": "It removes all delays", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy Item Exporter code accomplish?\n\nfrom scrapy.exporters import CsvItemExporter\n\nclass CsvPipeline:\n    def open_spider(self, spider):\n        self.file = open('output.csv', 'wb')\n        self.exporter = CsvItemExporter(self.file, fields_to_export=['name', 'price', 'url'])\n        self.exporter.start_exporting()\n    \n    def process_item(self, item, spider):\n        self.exporter.export_item(item)\n        return item\n    \n    def close_spider(self, spider):\n        self.exporter.finish_exporting()\n        self.file.close()", "option_a": "It reads CSV files", "option_b": "It exports scraped items to CSV with specified column order, managing file lifecycle with spider events", "option_c": "It imports CSV data into spiders", "option_d": "It only exports JSON", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing depth-limited link following?\n\ndef follow_links(soup, base_url, max_depth=2, current_depth=0):\n    if current_depth >= max_depth:\n        return []\n    \n    results = []\n    for link in soup.select('a[href]'):\n        href = urljoin(base_url, link['href'])\n        results.append({'url': href, 'depth': current_depth + 1})\n    return results", "option_a": "It follows links infinitely", "option_b": "It removes all links", "option_c": "It only follows the first link", "option_d": "It extracts links from a page but respects a maximum crawl depth to prevent unbounded crawling", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this BeautifulSoup code accomplish?\n\nhtml = '<div><span data-bind=\"text: productName\">Widget Pro</span></div>'\nsoup = BeautifulSoup(html, 'html.parser')\n# Find KnockoutJS bound elements\nbound_elements = soup.find_all(attrs={'data-bind': True})\nfor el in bound_elements:\n    binding = el['data-bind']\n    value = el.text\n    print(f'{binding}: {value}')", "option_a": "text: productName: Widget Pro", "option_b": "It fails because data-bind is not a standard attribute", "option_c": "Widget Pro", "option_d": "data-bind: text: productName", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Selenium code accomplish for handling dynamic dropdowns?\n\nfrom selenium.webdriver.support.ui import WebDriverWait\nfrom selenium.webdriver.support import expected_conditions as EC\n\n# Click to open dropdown\ndriver.find_element(By.CSS_SELECTOR, '.dropdown-trigger').click()\n\n# Wait for options to appear\nWebDriverWait(driver, 10).until(\n    EC.visibility_of_element_located((By.CSS_SELECTOR, '.dropdown-menu'))\n)\n\n# Select an option\ndriver.find_element(By.XPATH, \"//li[text()='Option 2']\").click()", "option_a": "It handles a custom JavaScript dropdown by clicking to open, waiting for visibility, then selecting an option", "option_b": "It creates a new dropdown", "option_c": "It only works with native HTML select elements", "option_d": "It scrolls the dropdown", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for comparing scraping approaches?\n\nimport time\nimport requests\nimport aiohttp\nimport asyncio\n\n# Synchronous\nstart = time.time()\nfor url in urls[:100]:\n    requests.get(url)\nsync_time = time.time() - start\n\n# Asynchronous\nasync def fetch_all():\n    async with aiohttp.ClientSession() as s:\n        return await asyncio.gather(*[s.get(u) for u in urls[:100]])\n\nstart = time.time()\nasyncio.run(fetch_all())\nasync_time = time.time() - start\n\nprint(f'Sync: {sync_time:.1f}s, Async: {async_time:.1f}s')", "option_a": "It proves synchronous is always faster", "option_b": "It benchmarks synchronous vs asynchronous scraping, demonstrating async's speed advantage for I/O-bound tasks", "option_c": "It only tests error handling", "option_d": "Both approaches take the same time", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling Content-Disposition headers when downloading files?\n\nimport re\n\ndef get_filename_from_response(resp):\n    cd = resp.headers.get('Content-Disposition', '')\n    if cd:\n        fname = re.findall(r'filename=\"?([^\"]+)\"?', cd)\n        if fname:\n            return fname[0]\n    # Fallback to URL\n    from urllib.parse import urlparse\n    return urlparse(resp.url).path.split('/')[-1] or 'download'", "option_a": "It always uses a fixed filename", "option_b": "It only handles PDF files", "option_c": "It renames existing files", "option_d": "It extracts the filename from Content-Disposition header with URL fallback for saving downloaded files correctly", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy middleware accomplish for request deduplication with custom logic?\n\nclass CustomDupeFilter:\n    def __init__(self):\n        self.seen = set()\n    \n    def request_seen(self, request):\n        # Custom fingerprint: URL without query params + method\n        from urllib.parse import urlparse\n        parsed = urlparse(request.url)\n        fp = f'{request.method}:{parsed.scheme}://{parsed.netloc}{parsed.path}'\n        if fp in self.seen:\n            return True\n        self.seen.add(fp)\n        return False", "option_a": "It deduplicates requests by URL path without query parameters, treating ?page=1 and ?page=2 as the same URL", "option_b": "It considers all URLs as unique", "option_c": "It only checks HTTP methods", "option_d": "It hashes the full URL including query params", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for scraping dynamic content with network idle detection?\n\nfrom playwright.async_api import async_playwright\n\nasync def scrape_after_network_idle(url):\n    async with async_playwright() as p:\n        browser = await p.chromium.launch()\n        page = await browser.new_page()\n        await page.goto(url, wait_until='networkidle')\n        # All XHR/fetch requests have completed\n        return await page.content()", "option_a": "It immediately returns before loading completes", "option_b": "It waits until there are no network requests for 500ms, ensuring all dynamic content has loaded", "option_c": "It waits for the DOMContentLoaded event only", "option_d": "It waits indefinitely", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling connection timeouts differently from read timeouts?\n\ntry:\n    resp = requests.get(url, timeout=(3, 10))\nexcept requests.exceptions.ConnectTimeout:\n    print('Could not connect to server')\nexcept requests.exceptions.ReadTimeout:\n    print('Server did not send data in time')", "option_a": "It handles connection and read timeouts with separate exception types for different recovery strategies", "option_b": "It uses the same timeout for both", "option_c": "It disables timeouts", "option_d": "It retries on any timeout", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does response.history contain in the requests library?\n\nresp = requests.get('http://old-domain.com')\nprint(resp.history)\nprint(resp.url)", "option_a": "A list of Response objects for each redirect that was followed before the final response", "option_b": "The browser history", "option_c": "Previous requests made in the session", "option_d": "The request body history", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code output for CSS attribute substring matching?\n\nhtml = '<a href=\"https://docs.python.org\">Docs</a><a href=\"https://pypi.org\">PyPI</a><a href=\"https://python.org\">Main</a>'\nsoup = BeautifulSoup(html, 'html.parser')\nresult = soup.select('a[href*=\"python\"]')\nprint([a.text for a in result])", "option_a": "['Docs', 'Main']", "option_b": "['Docs', 'PyPI', 'Main']", "option_c": "['Main']", "option_d": "['Docs']", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
