    {"question_text": "What does this code accomplish for extracting data from nested JSON within HTML?\n\nimport json\nfrom bs4 import BeautifulSoup\n\nhtml = '<script id=\"__NEXT_DATA__\" type=\"application/json\">{\"props\":{\"products\":[{\"id\":1,\"name\":\"Widget\"}]}}</script>'\nsoup = BeautifulSoup(html, 'html.parser')\nscript = soup.find('script', id='__NEXT_DATA__')\ndata = json.loads(script.string)\nprint(data['props']['products'][0]['name'])", "option_a": "Widget", "option_b": "Error - JSON in script tags cannot be parsed", "option_c": "None", "option_d": "{\"id\":1,\"name\":\"Widget\"}", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the purpose of the meta parameter in Scrapy requests for splash integration?\n\nyield scrapy.Request(url, meta={\n    'splash': {\n        'endpoint': 'render.html',\n        'args': {'wait': 2, 'timeout': 30}\n    }\n})", "option_a": "It adds metadata to the response", "option_b": "It tells Scrapy to use Splash (headless browser service) to render JavaScript with specified wait time", "option_c": "It caches the response", "option_d": "It sets request priority", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this code?\n\nfrom bs4 import BeautifulSoup\nhtml = '<p class=\"intro\">Hello <b class=\"name\">World</b></p>'\nsoup = BeautifulSoup(html, 'html.parser')\np = soup.find('p')\nprint(p.get('class'), p.find('b').get('class'))", "option_a": "['intro'] ['name']", "option_b": "'intro' 'name'", "option_c": "None None", "option_d": "intro name", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling authentication token refresh during scraping?\n\nclass TokenManager:\n    def __init__(self, auth_url, credentials):\n        self.auth_url = auth_url\n        self.credentials = credentials\n        self.token = None\n        self.expires_at = 0\n    \n    def get_token(self):\n        if time.time() >= self.expires_at - 60:  # Refresh 60s before expiry\n            resp = requests.post(self.auth_url, json=self.credentials)\n            data = resp.json()\n            self.token = data['access_token']\n            self.expires_at = time.time() + data['expires_in']\n        return self.token", "option_a": "It stores tokens permanently without refresh", "option_b": "It manages token lifecycle, proactively refreshing before expiry to maintain uninterrupted access", "option_c": "It creates new accounts for each request", "option_d": "It only works with OAuth1", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for scraping data from HTML5 data attributes?\n\nhtml = '<article data-id=\"42\" data-author=\"John\" data-published=\"2024-01-15\">Content</article>'\nsoup = BeautifulSoup(html, 'html.parser')\narticle = soup.find('article')\nmetadata = {k.replace('data-', ''): v for k, v in article.attrs.items() if k.startswith('data-')}\nprint(metadata)", "option_a": "{'id': '42', 'author': 'John', 'published': '2024-01-15'}", "option_b": "{'data-id': '42'}", "option_c": "{}", "option_d": "Error", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for maintaining a scraping session across multiple script runs?\n\nimport pickle\nimport requests\n\ndef save_session(session, path='session.pkl'):\n    with open(path, 'wb') as f:\n        pickle.dump(session.cookies, f)\n\ndef load_session(path='session.pkl'):\n    session = requests.Session()\n    try:\n        with open(path, 'rb') as f:\n            session.cookies = pickle.load(f)\n    except FileNotFoundError:\n        pass\n    return session", "option_a": "It creates a new session each time", "option_b": "It persists session cookies to disk so they can be restored across script runs", "option_c": "It encrypts session data", "option_d": "It only works with HTTPS sessions", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this XPath expression accomplish?\n\n//div[count(child::p) > 2]", "option_a": "Selects divs with exactly 2 paragraph children", "option_b": "Selects all div elements that have more than 2 direct p child elements", "option_c": "Counts all paragraphs on the page", "option_d": "Selects the 2nd div element", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for implementing request queuing with priority?\n\nimport heapq\n\nclass PriorityQueue:\n    def __init__(self):\n        self.heap = []\n        self.counter = 0\n    \n    def push(self, url, priority=0):\n        heapq.heappush(self.heap, (priority, self.counter, url))\n        self.counter += 1\n    \n    def pop(self):\n        if self.heap:\n            return heapq.heappop(self.heap)[2]\n        return None", "option_a": "It processes URLs randomly", "option_b": "It deduplicates URLs", "option_c": "It stores URLs alphabetically", "option_d": "It implements a priority queue for URLs where lower priority values are processed first (FIFO within same priority)", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What will this Selenium code produce for extracting table data?\n\ntable = driver.find_element(By.ID, 'data-table')\nrows = table.find_elements(By.TAG_NAME, 'tr')\ndata = []\nfor row in rows:\n    cells = row.find_elements(By.TAG_NAME, 'td')\n    data.append([cell.text for cell in cells])\n# data now contains all table rows", "option_a": "It only extracts the first row", "option_b": "It extracts all table data into a list of lists, where each inner list contains cell text for a row", "option_c": "It modifies the table content", "option_d": "It only works with header cells (th)", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for detecting changes in scraped content?\n\nimport difflib\n\ndef compare_versions(old_text, new_text):\n    differ = difflib.unified_diff(\n        old_text.splitlines(),\n        new_text.splitlines(),\n        lineterm=''\n    )\n    changes = list(differ)\n    return changes if changes else None", "option_a": "It merges two texts together", "option_b": "It generates a unified diff between two versions of scraped content to detect what changed", "option_c": "It counts words in both texts", "option_d": "It validates HTML structure", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the purpose of the 'meta' attribute in Scrapy Response objects?\n\ndef parse(self, response):\n    category = response.meta.get('category', 'default')\n    page_num = response.meta.get('page', 1)", "option_a": "It contains HTTP response headers", "option_b": "It carries arbitrary metadata passed from Request to its corresponding Response for maintaining state", "option_c": "It stores the response body", "option_d": "It contains cookies only", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for filtering out navigation and footer links during scraping?\n\ndef extract_content_links(soup, base_url):\n    # Exclude common non-content areas\n    exclude_selectors = ['nav', 'footer', 'header', '.sidebar', '.menu', '.breadcrumb']\n    for selector in exclude_selectors:\n        for element in soup.select(selector):\n            element.decompose()\n    \n    # Now extract links from remaining content\n    links = [urljoin(base_url, a['href']) for a in soup.select('a[href]')]\n    return links", "option_a": "It removes navigation/footer/sidebar elements before extracting links, focusing on content-area links only", "option_b": "It extracts all links including navigation", "option_c": "It only extracts navigation links", "option_d": "It validates all links", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling content that changes based on geolocation?\n\nsession = requests.Session()\n\n# Use a US-based proxy\nsession.proxies = {'https': 'http://us-proxy:8080'}\n\n# Set Accept-Language to match\nsession.headers.update({\n    'Accept-Language': 'en-US,en;q=0.9',\n})\n\nresp = session.get('http://international-site.com/products')", "option_a": "It disables geolocation", "option_b": "It makes requests appear to come from the US by using a US proxy and matching language headers", "option_c": "It blocks all international content", "option_d": "It translates the page to English", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does the following Scrapy code accomplish with the cb_kwargs parameter?\n\nyield scrapy.Request(\n    url,\n    callback=self.parse_detail,\n    cb_kwargs={'category': 'electronics', 'page': 5}\n)\n\ndef parse_detail(self, response, category, page):\n    yield {'title': response.css('h1::text').get(), 'category': category, 'page': page}", "option_a": "It passes keyword arguments directly to the callback function as function parameters", "option_b": "It sets request headers", "option_c": "It modifies the URL", "option_d": "It adds query parameters", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code demonstrate about handling chunked transfer encoding?\n\nresp = requests.get(url, stream=True)\nfor chunk in resp.iter_content(chunk_size=None):\n    # chunk_size=None means chunks are received as they arrive from the server\n    process_chunk(chunk)", "option_a": "It downloads the entire response at once", "option_b": "With chunk_size=None, it reads data as it arrives from the server, ideal for chunked transfer encoding", "option_c": "It creates fixed-size chunks", "option_d": "It only reads the first chunk", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for scraping an API that uses cursor pagination with opaque tokens?\n\ndef scrape_cursor_api(base_url, auth_header):\n    headers = {'Authorization': auth_header}\n    cursor = ''\n    all_items = []\n    while True:\n        params = {'limit': 200}\n        if cursor:\n            params['after'] = cursor\n        resp = requests.get(base_url, headers=headers, params=params)\n        data = resp.json()\n        all_items.extend(data['data'])\n        cursor = data.get('paging', {}).get('cursors', {}).get('after', '')\n        if not cursor or not data['data']:\n            break\n    return all_items", "option_a": "It only fetches the first batch", "option_b": "It iterates through API pages using opaque cursor tokens until all data is collected", "option_c": "It uses offset pagination", "option_d": "It fetches pages in reverse order", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Playwright code accomplish for handling authentication via cookies?\n\nasync def scrape_with_cookies(url, cookies):\n    async with async_playwright() as p:\n        browser = await p.chromium.launch()\n        context = await browser.new_context()\n        await context.add_cookies(cookies)\n        page = await context.new_page()\n        await page.goto(url)\n        return await page.content()", "option_a": "It clears all cookies", "option_b": "It sets pre-defined cookies on the browser context before navigating, enabling access to authenticated pages", "option_c": "It extracts cookies from the page", "option_d": "It only works with session cookies", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing a crawl frontier with URL normalization?\n\nfrom urllib.parse import urlparse, urlunparse, urlencode, parse_qs\n\ndef normalize_url(url):\n    parsed = urlparse(url.lower())\n    # Sort query parameters\n    params = parse_qs(parsed.query)\n    sorted_query = urlencode(sorted(params.items()), doseq=True)\n    # Remove default ports, trailing slashes\n    netloc = parsed.netloc.replace(':80', '').replace(':443', '')\n    path = parsed.path.rstrip('/') or '/'\n    return urlunparse((parsed.scheme, netloc, path, '', sorted_query, ''))", "option_a": "It validates URLs only", "option_b": "It normalizes URLs by lowercasing, sorting params, and removing defaults to prevent duplicate crawling of equivalent URLs", "option_c": "It shortens URLs", "option_d": "It encrypts URLs", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code output when using BeautifulSoup to find elements by multiple attributes?\n\nhtml = '<input type=\"text\" name=\"email\" required/><input type=\"text\" name=\"phone\"/><input type=\"password\" name=\"pass\"/>'\nsoup = BeautifulSoup(html, 'html.parser')\nresult = soup.find_all('input', attrs={'type': 'text', 'required': True})\nprint(len(result))", "option_a": "1", "option_b": "2", "option_c": "3", "option_d": "0", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling sites that vary content based on Accept-Language header?\n\n# Scrape multiple language versions\nlanguages = ['en-US', 'fr-FR', 'de-DE', 'ja-JP']\nresults = {}\nfor lang in languages:\n    headers = {'Accept-Language': lang}\n    resp = requests.get('http://site.com/products', headers=headers)\n    results[lang] = BeautifulSoup(resp.text, 'html.parser')", "option_a": "It translates pages automatically", "option_b": "It requests the same page in multiple languages by varying the Accept-Language header", "option_c": "It only gets the English version", "option_d": "It changes the browser locale permanently", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for scraping with request deduplication using Bloom filters?\n\nfrom pybloom_live import BloomFilter\n\nclass BloomDeduplicator:\n    def __init__(self, capacity=1000000, error_rate=0.001):\n        self.bloom = BloomFilter(capacity=capacity, error_rate=error_rate)\n    \n    def is_seen(self, url):\n        if url in self.bloom:\n            return True  # Probably seen (small false positive rate)\n        self.bloom.add(url)\n        return False", "option_a": "It uses exact set-based deduplication", "option_b": "It stores all URLs in a database", "option_c": "It guarantees zero false positives", "option_d": "It uses a memory-efficient Bloom filter for probabilistic URL deduplication with controlled false positive rate", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this BeautifulSoup code?\n\nhtml = '<div><a href=\"/a\">A</a><a href=\"/b\">B</a></div><div><a href=\"/c\">C</a></div>'\nsoup = BeautifulSoup(html, 'html.parser')\nfirst_div = soup.find('div')\nlinks = first_div.find_all('a')\nprint(len(links), [a['href'] for a in links])", "option_a": "2 ['/a', '/b']", "option_b": "3 ['/a', '/b', '/c']", "option_c": "1 ['/a']", "option_d": "0 []", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for building a retry queue for failed requests?\n\nfrom collections import deque\nimport time\n\nclass RetryQueue:\n    def __init__(self, max_retries=3):\n        self.queue = deque()\n        self.max_retries = max_retries\n    \n    def add_failed(self, url, attempt=0):\n        if attempt < self.max_retries:\n            delay = 2 ** attempt\n            self.queue.append((url, attempt + 1, time.time() + delay))\n    \n    def get_ready(self):\n        ready = []\n        now = time.time()\n        while self.queue and self.queue[0][2] <= now:\n            url, attempt, _ = self.queue.popleft()\n            ready.append((url, attempt))\n        return ready", "option_a": "It retries immediately without delay", "option_b": "It discards all failed requests", "option_c": "It queues failed requests with exponential backoff delays, releasing them when their wait time has elapsed", "option_d": "It retries indefinitely", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for cleaning HTML before text extraction?\n\nimport re\n\ndef clean_html_text(html_string):\n    # Remove script and style content\n    text = re.sub(r'<(script|style)[^>]*>.*?</\\1>', '', html_string, flags=re.DOTALL)\n    # Remove HTML tags\n    text = re.sub(r'<[^>]+>', ' ', text)\n    # Normalize whitespace\n    text = re.sub(r'\\s+', ' ', text)\n    # Decode HTML entities\n    import html\n    text = html.unescape(text)\n    return text.strip()", "option_a": "It performs multi-step HTML cleaning: removes scripts/styles, strips tags, normalizes whitespace, and decodes entities", "option_b": "It only removes script tags", "option_c": "It converts HTML to markdown", "option_d": "It validates HTML syntax", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing a scraper with respect for Crawl-delay in robots.txt?\n\nfrom urllib.robotparser import RobotFileParser\n\ndef get_crawl_delay(url, user_agent):\n    from urllib.parse import urlparse\n    parsed = urlparse(url)\n    rp = RobotFileParser()\n    rp.set_url(f'{parsed.scheme}://{parsed.netloc}/robots.txt')\n    rp.read()\n    delay = rp.crawl_delay(user_agent)\n    return delay if delay else 1.0  # Default 1 second if not specified", "option_a": "It always returns 0", "option_b": "It sets the delay to the maximum possible value", "option_c": "It ignores robots.txt", "option_d": "It reads the robots.txt Crawl-delay directive for the user agent, with a 1-second default fallback", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing browser fingerprint randomization?\n\nimport random\n\ndef random_viewport():\n    viewports = [\n        {'width': 1920, 'height': 1080},\n        {'width': 1366, 'height': 768},\n        {'width': 1440, 'height': 900},\n        {'width': 1536, 'height': 864},\n    ]\n    return random.choice(viewports)\n\ndef random_platform():\n    platforms = ['Win32', 'MacIntel', 'Linux x86_64']\n    return random.choice(platforms)", "option_a": "It always uses the same viewport", "option_b": "It randomizes browser characteristics (viewport, platform) to make each session look like a different user", "option_c": "It optimizes page rendering", "option_d": "It only affects mobile viewports", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this BeautifulSoup code demonstrate about finding the previous element?\n\nhtml = '<div><h2>Section 1</h2><p>Content 1</p><h2>Section 2</h2><p>Content 2</p></div>'\nsoup = BeautifulSoup(html, 'html.parser')\ncontent2 = soup.find('p', string='Content 2')\nsection_title = content2.find_previous('h2').text\nprint(section_title)", "option_a": "Section 1", "option_b": "Content 2", "option_c": "Section 2", "option_d": "None", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for creating a configurable scraper with dependency injection?\n\nclass Scraper:\n    def __init__(self, fetcher, parser, storage):\n        self.fetcher = fetcher\n        self.parser = parser\n        self.storage = storage\n    \n    def scrape(self, url):\n        html = self.fetcher.fetch(url)\n        data = self.parser.parse(html)\n        self.storage.save(data)\n        return data\n\n# Can inject different implementations\nscraper = Scraper(\n    fetcher=RequestsFetcher(),\n    parser=BeautifulSoupParser(),\n    storage=SQLiteStorage('data.db')\n)", "option_a": "It hard-codes all dependencies", "option_b": "It uses dependency injection for flexible, testable scraper components that can be swapped independently", "option_c": "It only works with one storage type", "option_d": "It creates circular dependencies", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling scraping of sites with anti-scraping JavaScript?\n\nfrom selenium import webdriver\nimport time\n\ndef bypass_cloudflare_wait(driver, url):\n    driver.get(url)\n    # Cloudflare typically shows a challenge for 5 seconds\n    time.sleep(6)\n    # Check if we passed the challenge\n    if 'Just a moment' not in driver.page_source:\n        return driver.page_source\n    else:\n        raise Exception('Failed to bypass challenge')", "option_a": "It waits for Cloudflare's JavaScript challenge to complete before extracting page content", "option_b": "It instantly bypasses all protections", "option_c": "It solves CAPTCHAs", "option_d": "It works without any browser", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for safe concurrent writing of scraped data?\n\nimport threading\nimport json\n\nclass ThreadSafeWriter:\n    def __init__(self, filepath):\n        self.filepath = filepath\n        self.lock = threading.Lock()\n        self.file = open(filepath, 'a')\n    \n    def write_item(self, item):\n        with self.lock:\n            self.file.write(json.dumps(item) + '\\n')\n            self.file.flush()\n    \n    def close(self):\n        self.file.close()", "option_a": "It writes without any synchronization", "option_b": "It uses a threading lock to ensure only one thread writes to the file at a time, preventing data corruption", "option_c": "It writes to multiple files simultaneously", "option_d": "It only works with single-threaded code", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for handling paginated search results with unknown total?\n\ndef scrape_until_empty(base_url, query):\n    page = 1\n    all_results = []\n    consecutive_empty = 0\n    \n    while consecutive_empty < 2:  # Stop after 2 consecutive empty pages\n        resp = requests.get(base_url, params={'q': query, 'page': page})\n        soup = BeautifulSoup(resp.text, 'html.parser')\n        results = soup.select('.result-item')\n        \n        if not results:\n            consecutive_empty += 1\n        else:\n            consecutive_empty = 0\n            all_results.extend(results)\n        page += 1\n    \n    return all_results", "option_a": "It stops after exactly one empty page", "option_b": "It only scrapes 2 pages total", "option_c": "It never stops", "option_d": "It scrapes pages until 2 consecutive empty pages are found, handling potential gaps in results", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Selenium code accomplish for extracting shadow DOM content?\n\nshadow_host = driver.find_element(By.CSS_SELECTOR, 'custom-element')\nshadow_root = driver.execute_script('return arguments[0].shadowRoot', shadow_host)\ninner_element = shadow_root.find_element(By.CSS_SELECTOR, '.inner-content')\nprint(inner_element.text)", "option_a": "It modifies the shadow DOM", "option_b": "It accesses elements inside a shadow DOM by getting the shadow root via JavaScript and then querying within it", "option_c": "It creates a new shadow DOM", "option_d": "It removes the shadow DOM", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this code?\n\nfrom bs4 import BeautifulSoup\nhtml = '<div>Before<div class=\"nested\">Inside</div>After</div>'\nsoup = BeautifulSoup(html, 'html.parser')\nouter = soup.find('div')\nprint(list(outer.stripped_strings))", "option_a": "['Before', 'Inside', 'After']", "option_b": "['Before', 'After']", "option_c": "['BeforeInsideAfter']", "option_d": "['Inside']", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling sites that serve different content to mobile vs desktop?\n\nmobile_headers = {\n    'User-Agent': 'Mozilla/5.0 (iPhone; CPU iPhone OS 14_0 like Mac OS X) AppleWebKit/605.1.15'\n}\ndesktop_headers = {\n    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'\n}\n\nmobile_resp = requests.get(url, headers=mobile_headers)\ndesktop_resp = requests.get(url, headers=desktop_headers)", "option_a": "Both requests return identical content", "option_b": "It requests both mobile and desktop versions of a page by changing the User-Agent to respective device strings", "option_c": "It only gets the mobile version", "option_d": "It changes the actual device type", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing domain-specific scraping rules?\n\nclass ScrapeRules:\n    rules = {\n        'example.com': {'delay': 2, 'max_pages': 100, 'allowed_paths': ['/products', '/categories']},\n        'other-site.com': {'delay': 5, 'max_pages': 50, 'allowed_paths': ['/api']},\n    }\n    \n    @classmethod\n    def get_rules(cls, url):\n        from urllib.parse import urlparse\n        domain = urlparse(url).netloc\n        return cls.rules.get(domain, {'delay': 3, 'max_pages': 10, 'allowed_paths': ['/']})", "option_a": "It applies the same rules to all sites", "option_b": "It provides domain-specific scraping configurations with sensible defaults for unknown domains", "option_c": "It blocks specific domains", "option_d": "It only stores URLs", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for extracting structured JSON-LD data from e-commerce pages?\n\ndef extract_json_ld(soup):\n    scripts = soup.find_all('script', type='application/ld+json')\n    structured_data = []\n    for script in scripts:\n        try:\n            data = json.loads(script.string)\n            structured_data.append(data)\n        except (json.JSONDecodeError, TypeError):\n            continue\n    return structured_data", "option_a": "It only parses the first JSON-LD script", "option_b": "It validates JSON-LD schema", "option_c": "It creates JSON-LD data", "option_d": "It extracts and parses all JSON-LD structured data blocks from a page, handling parse errors gracefully", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the output of this code?\n\nfrom bs4 import BeautifulSoup\nhtml = '<ul><li>Item 1</li><!-- hidden --><li>Item 2</li></ul>'\nsoup = BeautifulSoup(html, 'html.parser')\nitems = soup.find_all('li')\nprint(len(items))", "option_a": "2", "option_b": "3", "option_c": "1", "option_d": "0", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for implementing exponential backoff with jitter?\n\nimport random\nimport time\n\ndef backoff_with_jitter(attempt, base=1, cap=60):\n    exp_delay = min(base * (2 ** attempt), cap)\n    jitter = random.uniform(0, exp_delay)\n    return jitter\n\n# Usage in retry loop\nfor attempt in range(5):\n    try:\n        resp = requests.get(url)\n        resp.raise_for_status()\n        break\n    except requests.RequestException:\n        delay = backoff_with_jitter(attempt)\n        time.sleep(delay)", "option_a": "It uses fixed delays", "option_b": "It always waits the maximum time", "option_c": "It adds randomized jitter to exponential backoff to prevent thundering herd problems when multiple scrapers retry simultaneously", "option_d": "It removes delays entirely", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy extension accomplish?\n\nclass ClosedDomainFilter:\n    def process_request(self, request, spider):\n        from urllib.parse import urlparse\n        domain = urlparse(request.url).netloc\n        allowed = spider.allowed_domains\n        if allowed and domain not in allowed:\n            raise IgnoreRequest(f'Domain {domain} not in allowed_domains')\n        return None", "option_a": "It allows all domains", "option_b": "It adds new domains to the allowed list", "option_c": "It only processes requests from specific IPs", "option_d": "It enforces domain restrictions by dropping requests to domains not in the spider's allowed_domains list", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for scraping with request throttling per domain?\n\nimport time\nfrom collections import defaultdict\n\nclass PerDomainThrottler:\n    def __init__(self, default_delay=1.0):\n        self.last_request_time = defaultdict(float)\n        self.default_delay = default_delay\n        self.domain_delays = {}\n    \n    def set_delay(self, domain, delay):\n        self.domain_delays[domain] = delay\n    \n    def throttle(self, url):\n        from urllib.parse import urlparse\n        domain = urlparse(url).netloc\n        delay = self.domain_delays.get(domain, self.default_delay)\n        elapsed = time.time() - self.last_request_time[domain]\n        if elapsed < delay:\n            time.sleep(delay - elapsed)\n        self.last_request_time[domain] = time.time()", "option_a": "It applies one global delay for all domains", "option_b": "It implements per-domain rate limiting with configurable delays, allowing different speeds for different sites", "option_c": "It blocks specific domains", "option_d": "It removes all delays", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for detecting content language of scraped pages?\n\nfrom langdetect import detect\n\ndef get_page_language(soup):\n    # Try HTML lang attribute first\n    html_tag = soup.find('html')\n    if html_tag and html_tag.get('lang'):\n        return html_tag['lang'][:2]\n    # Fall back to content detection\n    text = soup.get_text(strip=True)[:1000]\n    try:\n        return detect(text)\n    except:\n        return 'unknown'", "option_a": "It translates the page", "option_b": "It always returns English", "option_c": "It only checks the HTML lang attribute", "option_d": "It detects page language using HTML lang attribute first, then falls back to content-based language detection", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code output?\n\nfrom bs4 import BeautifulSoup\nhtml = '<div>Text1<br>Text2<br/>Text3</div>'\nsoup = BeautifulSoup(html, 'html.parser')\ndiv = soup.find('div')\nlines = [str(item).strip() for item in div.children if str(item).strip()]\nprint(len(lines))", "option_a": "5", "option_b": "3", "option_c": "2", "option_d": "1", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing a URL pattern matcher for crawling?\n\nimport re\n\nclass URLMatcher:\n    def __init__(self, patterns):\n        self.patterns = [re.compile(p) for p in patterns]\n    \n    def matches(self, url):\n        return any(p.search(url) for p in self.patterns)\n\n# Only follow product and category pages\nmatcher = URLMatcher([\n    r'/products?/[\\w-]+',\n    r'/categor(y|ies)/[\\w-]+',\n    r'/item/\\d+',\n])\n\nif matcher.matches('/products/blue-widget'):\n    # follow this link\n    pass", "option_a": "It matches all URLs", "option_b": "It filters URLs against regex patterns to control which links the crawler follows", "option_c": "It validates URL syntax", "option_d": "It shortens URLs", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing a respectful scraper that checks server load?\n\ndef check_server_health(url):\n    try:\n        start = time.time()\n        resp = requests.head(url, timeout=5)\n        response_time = time.time() - start\n        \n        if response_time > 3.0:\n            return 'slow'  # Server under load\n        elif resp.status_code >= 500:\n            return 'error'  # Server having issues\n        else:\n            return 'healthy'\n    except requests.RequestException:\n        return 'unreachable'", "option_a": "It always reports healthy", "option_b": "It uses a lightweight HEAD request to assess server health before sending heavy scraping requests", "option_c": "It downloads the full page", "option_d": "It pings the server using ICMP", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for extracting specific sections from a Wikipedia-style page?\n\ndef extract_section(soup, section_title):\n    heading = soup.find(['h2', 'h3'], string=re.compile(section_title, re.I))\n    if not heading:\n        return None\n    \n    content = []\n    for sibling in heading.find_next_siblings():\n        if sibling.name in ['h2', 'h3']:\n            break  # Stop at next section\n        content.append(sibling.get_text(strip=True))\n    return '\\n'.join(content)", "option_a": "It extracts the entire page", "option_b": "It removes the section", "option_c": "It only returns the heading text", "option_d": "It extracts text between two headings, capturing a specific named section from a structured page", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing a scraper health dashboard?\n\nclass ScraperMetrics:\n    def __init__(self):\n        self.requests_made = 0\n        self.requests_failed = 0\n        self.items_scraped = 0\n        self.bytes_downloaded = 0\n        self.start_time = time.time()\n    \n    def summary(self):\n        elapsed = time.time() - self.start_time\n        return {\n            'uptime_seconds': elapsed,\n            'requests_per_second': self.requests_made / elapsed,\n            'success_rate': (self.requests_made - self.requests_failed) / max(self.requests_made, 1),\n            'items_per_minute': self.items_scraped / (elapsed / 60),\n        }", "option_a": "It only tracks errors", "option_b": "It collects comprehensive scraping metrics and calculates derived statistics like rates and success ratios", "option_c": "It sends metrics to a monitoring service", "option_d": "It limits scraping speed", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code demonstrate about BeautifulSoup's handling of self-closing tags?\n\nhtml = '<div><br><hr><img src=\"x.jpg\"><input type=\"text\"></div>'\nsoup = BeautifulSoup(html, 'html.parser')\nprint(soup.find('br').name, soup.find('br').string)", "option_a": "br None", "option_b": "br ''", "option_c": "Error - self-closing tags cannot be found", "option_d": "None None", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Scrapy configuration accomplish for memory management?\n\nMEMUSAGE_ENABLED = True\nMEMUSAGE_LIMIT_MB = 512\nMEMUSAGE_WARNING_MB = 400\nMEMUSAGE_NOTIFY_MAIL = ['admin@company.com']", "option_a": "It allocates more memory to the spider", "option_b": "It compresses data in memory", "option_c": "It limits the response size", "option_d": "It monitors memory usage, warns at 400MB, and shuts down the spider at 512MB to prevent system crashes", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing content extraction using readability algorithms?\n\nfrom readability import Document\n\ndef extract_article(html):\n    doc = Document(html)\n    return {\n        'title': doc.title(),\n        'content': doc.summary(),  # Cleaned article HTML\n        'short_title': doc.short_title()\n    }", "option_a": "It extracts all HTML from the page", "option_b": "It formats text for printing", "option_c": "It only extracts the title", "option_d": "It uses a readability algorithm to extract the main article content, removing boilerplate (ads, navigation, etc.)", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for implementing crawl scheduling?\n\nimport schedule\nimport time\n\ndef daily_scrape():\n    urls = get_urls_to_scrape()\n    for url in urls:\n        scrape_and_store(url)\n        time.sleep(2)\n\nschedule.every().day.at('02:00').do(daily_scrape)\n\nwhile True:\n    schedule.run_pending()\n    time.sleep(60)", "option_a": "It runs the scraper continuously without pause", "option_b": "It schedules the scraper to run daily at 2:00 AM, ideal for regular data collection with minimal server impact", "option_c": "It only runs once", "option_d": "It schedules multiple scrapers simultaneously", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling sites that use hash-based routing (SPAs)?\n\n# Hash-based routes like: http://site.com/#/products/123\n# These don't trigger new HTTP requests\nfrom playwright.async_api import async_playwright\n\nasync def scrape_hash_routes(base_url, routes):\n    async with async_playwright() as p:\n        browser = await p.chromium.launch()\n        page = await browser.new_page()\n        results = []\n        for route in routes:\n            await page.goto(f'{base_url}#{route}')\n            await page.wait_for_selector('.content-loaded')\n            content = await page.inner_text('.main-content')\n            results.append(content)\n        return results", "option_a": "It uses a browser to navigate hash-based SPA routes that only change content client-side via JavaScript", "option_b": "It makes separate HTTP requests for each hash route", "option_c": "It ignores hash routes", "option_d": "It strips hashes from URLs", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for building a generic data extractor using CSS selector mappings?\n\ndef extract_by_mapping(soup, mapping):\n    result = {}\n    for field, selector in mapping.items():\n        element = soup.select_one(selector)\n        result[field] = element.get_text(strip=True) if element else None\n    return result\n\n# Site-specific configuration\namazon_mapping = {\n    'title': '#productTitle',\n    'price': '.a-price .a-offscreen',\n    'rating': '#acrPopover .a-icon-alt',\n    'availability': '#availability span',\n}", "option_a": "It only works with one website", "option_b": "It creates a configurable extractor where field-to-selector mappings can be defined per site without code changes", "option_c": "It validates HTML structure", "option_d": "It generates CSS selectors automatically", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this Selenium code accomplish for handling browser alerts and popups?\n\nfrom selenium.webdriver.common.alert import Alert\nfrom selenium.common.exceptions import NoAlertPresentException\n\ndef dismiss_alerts(driver):\n    try:\n        alert = Alert(driver)\n        alert.dismiss()\n        return True\n    except NoAlertPresentException:\n        return False", "option_a": "It creates new alerts", "option_b": "It safely dismisses any JavaScript alert/confirm dialog if present, without crashing if none exists", "option_c": "It accepts all alerts", "option_d": "It blocks alerts from appearing", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for rate-limiting concurrent async requests?\n\nimport asyncio\n\nclass AsyncRateLimiter:\n    def __init__(self, rate_per_second):\n        self.rate = rate_per_second\n        self.semaphore = asyncio.Semaphore(rate_per_second)\n        self._tokens = rate_per_second\n        self._updated_at = asyncio.get_event_loop().time()\n    \n    async def acquire(self):\n        await self.semaphore.acquire()\n        asyncio.get_event_loop().call_later(1.0 / self.rate, self.semaphore.release)", "option_a": "It allows unlimited concurrent requests", "option_b": "It limits async requests to a fixed rate per second by releasing semaphore tokens on a timer", "option_c": "It blocks all requests", "option_d": "It only works with synchronous code", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for parsing complex nested HTML structures?\n\nhtml = '''<div class=\"product-grid\">\n  <div class=\"product\" data-id=\"1\">\n    <h3><a href=\"/p/1\">Widget A</a></h3>\n    <div class=\"variants\">\n      <span class=\"variant\" data-color=\"red\">Red</span>\n      <span class=\"variant\" data-color=\"blue\">Blue</span>\n    </div>\n  </div>\n</div>'''\nsoup = BeautifulSoup(html, 'html.parser')\nproducts = []\nfor card in soup.select('.product'):\n    product = {\n        'id': card['data-id'],\n        'name': card.select_one('h3 a').text,\n        'url': card.select_one('h3 a')['href'],\n        'variants': [v['data-color'] for v in card.select('.variant')]\n    }\n    products.append(product)\nprint(products[0]['variants'])", "option_a": "['Red', 'Blue']", "option_b": "Error", "option_c": "[]", "option_d": "['red', 'blue']", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing a crawl budget management system?\n\nclass CrawlBudget:\n    def __init__(self, max_requests=10000, max_time_hours=4):\n        self.max_requests = max_requests\n        self.max_time = max_time_hours * 3600\n        self.requests_made = 0\n        self.start_time = time.time()\n    \n    def can_continue(self):\n        if self.requests_made >= self.max_requests:\n            return False\n        if time.time() - self.start_time >= self.max_time:\n            return False\n        return True\n    \n    def record_request(self):\n        self.requests_made += 1", "option_a": "It allows unlimited scraping", "option_b": "It enforces both request count and time-based limits to control total crawl resource usage", "option_c": "It only tracks time", "option_d": "It only tracks request count", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for handling dynamic table data that loads via AJAX?\n\nfrom selenium.webdriver.support.ui import WebDriverWait\nfrom selenium.webdriver.support import expected_conditions as EC\n\ndef scrape_dynamic_table(driver, url):\n    driver.get(url)\n    # Wait for table data to load\n    WebDriverWait(driver, 20).until(\n        EC.presence_of_element_located((By.CSS_SELECTOR, 'table tbody tr'))\n    )\n    # Now extract data\n    rows = driver.find_elements(By.CSS_SELECTOR, 'table tbody tr')\n    return [[cell.text for cell in row.find_elements(By.TAG_NAME, 'td')] for row in rows]", "option_a": "It waits for dynamically loaded table rows to appear before extracting data, handling AJAX-loaded tables", "option_b": "It only gets static table content", "option_c": "It creates a new table", "option_d": "It modifies table content", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing a web scraping data pipeline with validation?\n\nfrom dataclasses import dataclass, field\nfrom typing import Optional\n\n@dataclass\nclass ScrapedProduct:\n    name: str\n    price: float\n    url: str\n    category: str = 'uncategorized'\n    image_url: Optional[str] = None\n    \n    def __post_init__(self):\n        if self.price < 0:\n            raise ValueError(f'Invalid price: {self.price}')\n        if not self.url.startswith('http'):\n            raise ValueError(f'Invalid URL: {self.url}')", "option_a": "It stores data without validation", "option_b": "It uses dataclasses with post-init validation to ensure scraped data meets quality requirements", "option_c": "It creates database tables", "option_d": "It only validates URLs", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code output when using CSS selectors for attribute presence?\n\nhtml = '<input name=\"q\" type=\"text\"><input name=\"submit\" type=\"submit\" disabled><input name=\"hidden\" type=\"hidden\">'\nsoup = BeautifulSoup(html, 'html.parser')\nresult = soup.select('input[disabled]')\nprint(len(result), result[0]['name'] if result else None)", "option_a": "1 submit", "option_b": "2 q", "option_c": "0 None", "option_d": "3 q", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the correct approach to extract data from a website using both CSS selectors and XPath?\n\nfrom lxml import etree\n\ndef hybrid_extract(html):\n    tree = etree.HTML(html)\n    # XPath for complex conditions\n    prices = tree.xpath('//span[contains(@class, \"price\") and number(translate(., \"$,\", \"\")) > 10]/text()')\n    # CSS via BeautifulSoup for simpler selections\n    soup = BeautifulSoup(html, 'html.parser')\n    titles = [h.text for h in soup.select('h2.product-title')]", "option_a": "You can only use one parsing method per page", "option_b": "XPath and CSS selectors are incompatible", "option_c": "You can combine lxml XPath (for complex conditions) with BeautifulSoup CSS selectors (for simpler ones) for optimal extraction", "option_d": "BeautifulSoup supports XPath natively", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for implementing a scraper that respects site-specific crawl rules?\n\nclass SiteConfig:\n    configs = {\n        'example.com': {\n            'rate_limit': 2,  # requests per second\n            'respect_robots': True,\n            'user_agent': 'FriendlyBot/1.0',\n            'selectors': {'title': 'h1', 'price': '.price', 'desc': '.description'}\n        }\n    }\n    \n    @classmethod\n    def get(cls, domain):\n        return cls.configs.get(domain, cls.configs.get('default', {}))", "option_a": "It hard-codes behavior for all sites", "option_b": "It generates configurations automatically", "option_c": "It blocks all unconfigured sites", "option_d": "It provides site-specific scraping configurations including rate limits, selectors, and compliance settings", "correct_answer": "D", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What is the purpose of requests.Session().max_redirects?\n\nsession = requests.Session()\nsession.max_redirects = 5\ntry:\n    resp = session.get('http://redirect-loop.com')\nexcept requests.exceptions.TooManyRedirects:\n    print('Redirect loop detected')", "option_a": "It allows unlimited redirects", "option_b": "It sets the total request limit", "option_c": "It limits the maximum number of redirects to follow before raising TooManyRedirects, preventing infinite redirect loops", "option_d": "It counts total pages visited", "correct_answer": "C", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code pattern accomplish for handling dynamically generated form tokens?\n\ndef submit_form_with_dynamic_tokens(session, form_url, submit_url, form_data):\n    # Step 1: Get form page to extract dynamic tokens\n    resp = session.get(form_url)\n    soup = BeautifulSoup(resp.text, 'html.parser')\n    \n    # Extract all hidden inputs\n    hidden_fields = {}\n    for hidden in soup.select('input[type=hidden]'):\n        name = hidden.get('name')\n        value = hidden.get('value', '')\n        if name:\n            hidden_fields[name] = value\n    \n    # Merge with user data\n    payload = {**hidden_fields, **form_data}\n    return session.post(submit_url, data=payload)", "option_a": "It extracts dynamic hidden tokens (CSRF, nonce, etc.) from a form page and includes them in the submission", "option_b": "It ignores hidden form fields", "option_c": "It only submits visible fields", "option_d": "It creates new hidden fields", "correct_answer": "A", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this code accomplish for implementing a web scraper with circuit breaker pattern?\n\nclass CircuitBreaker:\n    def __init__(self, failure_threshold=5, reset_timeout=60):\n        self.failures = 0\n        self.threshold = failure_threshold\n        self.reset_timeout = reset_timeout\n        self.last_failure_time = 0\n        self.state = 'closed'  # closed, open, half-open\n    \n    def call(self, func, *args):\n        if self.state == 'open':\n            if time.time() - self.last_failure_time > self.reset_timeout:\n                self.state = 'half-open'\n            else:\n                raise CircuitOpenError('Circuit is open')\n        try:\n            result = func(*args)\n            self.failures = 0\n            self.state = 'closed'\n            return result\n        except Exception:\n            self.failures += 1\n            self.last_failure_time = time.time()\n            if self.failures >= self.threshold:\n                self.state = 'open'\n            raise", "option_a": "It retries indefinitely", "option_b": "It stops making requests after repeated failures (opens circuit), then gradually tests recovery after a timeout", "option_c": "It only handles network errors", "option_d": "It always keeps the circuit closed", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
    {"question_text": "What does this BeautifulSoup code accomplish for extracting email-protected content?\n\nhtml = '<span class=\"__cf_email__\" data-cfemail=\"0b6e636a7f6a25786e4b6e736a667b676e256864\">email protected</span>'\nsoup = BeautifulSoup(html, 'html.parser')\nencoded = soup.find(class_='__cf_email__')\nif encoded:\n    # Cloudflare email protection decoding\n    data = encoded['data-cfemail']\n    key = int(data[:2], 16)\n    email = ''.join(chr(int(data[i:i+2], 16) ^ key) for i in range(2, len(data), 2))\n    print(email)", "option_a": "It removes email addresses", "option_b": "It decodes Cloudflare's email protection encoding to reveal the actual email address", "option_c": "It encrypts email addresses", "option_d": "It validates email format", "correct_answer": "B", "difficulty": "advanced", "topic": "web_scraping"},
